#[derive(Clone, Copy, Debug, Eq, PartialEq)]
enum DialogLifecycleSmokeStep {
    WaitMainFrame,
    WaitDialogFrame,
    WaitMainFrameAfterClose,
    Complete,
    Failed,
}

#[derive(Clone, Copy, Debug)]
struct DialogLifecycleSmoke {
    step: DialogLifecycleSmokeStep,
    kind: ShellDialogWindowKind,
    close_frame: u64,
    cycles_remaining: usize,
}

impl DialogLifecycleSmoke {
    fn from_env() -> Option<Self> {
        dialog_lifecycle_autosmoke_enabled().then_some(Self {
            step: DialogLifecycleSmokeStep::WaitMainFrame,
            kind: dialog_lifecycle_autosmoke_kind_from_env(),
            close_frame: 0,
            cycles_remaining: dialog_lifecycle_autosmoke_cycles_from_env(),
        })
    }

    fn pending(self) -> bool {
        !matches!(
            self.step,
            DialogLifecycleSmokeStep::Complete | DialogLifecycleSmokeStep::Failed
        )
    }
}

fn dialog_lifecycle_autosmoke_cycles_from_env() -> usize {
    env::var_os("FIKA_WGPU_AUTOSMOKE_DIALOG_CYCLES")
        .and_then(|value| value.to_string_lossy().trim().parse::<usize>().ok())
        .filter(|cycles| *cycles > 0)
        .unwrap_or(1)
}

fn dialog_lifecycle_autosmoke_kind_from_env() -> ShellDialogWindowKind {
    let Some(value) = env::var_os("FIKA_WGPU_AUTOSMOKE_DIALOG_KIND") else {
        return ShellDialogWindowKind::Create;
    };
    match value.to_string_lossy().trim().to_ascii_lowercase().as_str() {
        "open-with" | "open_with" | "openwith" => ShellDialogWindowKind::OpenWith,
        "rename" => ShellDialogWindowKind::Rename,
        _ => ShellDialogWindowKind::Create,
    }
}

fn window_title(scene: &ShellScene) -> String {
    let view_mode = scene.active_view_mode();
    if let Some(split_pane) = scene.panes.get(ShellPaneId::SLOT_1) {
        format!(
            "{} | {} [{}]",
            scene.panes[ShellPaneId::SLOT_0].path.display(),
            split_pane.path.display(),
            view_mode.as_str()
        )
    } else {
        format!(
            "{} [{}]",
            scene.panes[ShellPaneId::SLOT_0].path.display(),
            view_mode.as_str()
        )
    }
}

struct FikaWgpuApp {
    scene: ShellScene,
    mime_applications: MimeApplicationCache,
    settings_path: PathBuf,
    directory_watchers: ShellDirectoryWatcherRuntime,
    async_task_tx: Sender<ShellAsyncTaskResult>,
    async_task_rx: Receiver<ShellAsyncTaskResult>,
    active_task_controllers: HashMap<ShellTaskId, OperationController>,
    active_task_base_details: HashMap<ShellTaskId, String>,
    next_task_id: ShellTaskId,
    modifiers: Modifiers,
    // Drop order matters: renderer owns a surface tied to the window handle.
    renderer: Option<WgpuState>,
    dialog_windows: ShellDialogWindows,
    dialog_close_main_close_guard_until: Option<Instant>,
    clipboard: Option<ShellClipboard>,
    window: Option<Arc<dyn Window>>,
    cursor_icon: CursorIcon,
    pending_redraw_frames: u8,
    pending_render_reason: Option<&'static str>,
    last_location_text_caret_dirty_value: u64,
    last_open_with_text_caret_dirty_value: u64,
    auto_cycle_views: bool,
    next_auto_cycle: Instant,
    autosmoke_zoom_actions: VecDeque<ZoomAction>,
    next_autosmoke_zoom: Instant,
    autosmoke_zoom_interval: Duration,
    autosmoke_zoom_allow_pending_redraw: bool,
    autosmoke_scroll_actions: VecDeque<AutosmokeScrollAction>,
    next_autosmoke_scroll: Instant,
    autosmoke_scroll_interval: Duration,
    autosmoke_scroll_allow_pending_redraw: bool,
    dialog_lifecycle_smoke: Option<DialogLifecycleSmoke>,
}

impl FikaWgpuApp {
    fn new(
        scene: ShellScene,
        auto_cycle_views: bool,
        settings_path: PathBuf,
        event_loop_proxy: EventLoopProxy,
    ) -> Self {
        let (async_task_tx, async_task_rx) = mpsc::channel();
        let autosmoke_zoom = autosmoke_zoom_config();
        let autosmoke_scroll = autosmoke_scroll_config(SCROLL_LINE_PX * 2.0);
        let mut directory_watchers = ShellDirectoryWatcherRuntime::new(event_loop_proxy);
        directory_watchers.sync_with_scene(&scene);
        Self {
            scene,
            mime_applications: MimeApplicationCache::load(),
            settings_path,
            directory_watchers,
            async_task_tx,
            async_task_rx,
            active_task_controllers: HashMap::new(),
            active_task_base_details: HashMap::new(),
            next_task_id: 1,
            modifiers: Modifiers::default(),
            renderer: None,
            dialog_windows: ShellDialogWindows::default(),
            dialog_close_main_close_guard_until: None,
            clipboard: None,
            window: None,
            cursor_icon: CursorIcon::Default,
            pending_redraw_frames: 0,
            pending_render_reason: None,
            last_location_text_caret_dirty_value: 0,
            last_open_with_text_caret_dirty_value: 0,
            auto_cycle_views,
            next_auto_cycle: Instant::now() + AUTO_CYCLE_INTERVAL,
            autosmoke_zoom_actions: autosmoke_zoom.actions,
            next_autosmoke_zoom: Instant::now() + autosmoke_zoom.interval,
            autosmoke_zoom_interval: autosmoke_zoom.interval,
            autosmoke_zoom_allow_pending_redraw: autosmoke_zoom.allow_pending_redraw,
            autosmoke_scroll_actions: autosmoke_scroll.actions,
            next_autosmoke_scroll: Instant::now() + autosmoke_scroll.interval,
            autosmoke_scroll_interval: autosmoke_scroll.interval,
            autosmoke_scroll_allow_pending_redraw: autosmoke_scroll.allow_pending_redraw,
            dialog_lifecycle_smoke: DialogLifecycleSmoke::from_env(),
        }
    }

    fn set_window_cursor(&mut self, cursor_icon: CursorIcon) {
        if self.cursor_icon == cursor_icon {
            return;
        }
        self.cursor_icon = cursor_icon;
        if let Some(window) = self.window.as_ref() {
            window.set_cursor(WinitCursor::Icon(cursor_icon));
        }
    }

    fn set_open_with_dialog_cursor(&mut self, cursor_icon: CursorIcon) {
        self.dialog_windows
            .set_cursor(ShellDialogWindowKind::OpenWith, cursor_icon);
    }

    fn update_window_cursor_for_scene(&mut self, size: PhysicalSize<u32>) {
        self.set_window_cursor(self.scene.cursor_icon(size));
    }

    fn update_open_with_dialog_cursor_for_scene(&mut self, size: PhysicalSize<u32>) {
        self.set_open_with_dialog_cursor(self.scene.open_with_chooser_cursor_icon(size));
    }

    fn request_main_redraw(&self) {
        if let Some(window) = self.window.as_ref() {
            window.request_redraw();
        }
    }

    fn request_open_with_dialog_redraw(&self) -> bool {
        self.request_dialog_redraw(ShellDialogWindowKind::OpenWith)
    }

    fn request_dialog_redraw(&self, kind: ShellDialogWindowKind) -> bool {
        self.dialog_windows.request_redraw(kind)
    }

    fn dialog_close_guard_trace(&self) -> String {
        let Some(deadline) = self.dialog_close_main_close_guard_until else {
            return "none".to_string();
        };
        let now = Instant::now();
        if deadline >= now {
            format!(
                "active:{}ms",
                deadline.saturating_duration_since(now).as_millis()
            )
        } else {
            format!(
                "expired:{}ms",
                now.saturating_duration_since(deadline).as_millis()
            )
        }
    }

    fn trace_window_event(&self, window_id: WindowId, event: &WindowEvent) {
        if !fika_dialog_trace_enabled() {
            return;
        }
        if window_event_trace_is_high_volume(event) && !fika_dialog_trace_verbose_enabled() {
            return;
        }
        let main_id = self.window.as_ref().map(|window| window.id());
        let dialog_kind = self.dialog_windows.window_kind_for_id(window_id);
        let recently_closed = self.dialog_windows.is_recently_closed_window(window_id);
        let role = if main_id == Some(window_id) {
            "main"
        } else if dialog_kind.is_some() {
            "dialog"
        } else if recently_closed {
            "recently-closed-dialog"
        } else {
            "unknown"
        };
        fika_dialog_trace!(
            "[fika-wgpu] window-event event={} window={:?} role={} main={:?} dialog={} recently_closed={} modal={} guard={}",
            window_event_label(event),
            window_id,
            role,
            main_id,
            dialog_kind
                .map(ShellDialogWindowKind::as_str)
                .unwrap_or("none"),
            recently_closed as u8,
            self.dialog_windows.has_modal_window() as u8,
            self.dialog_close_guard_trace()
        );
    }

    fn exit_event_loop(&self, event_loop: &dyn ActiveEventLoop, reason: &'static str) {
        fika_log!(
            "[fika-wgpu] event-loop-exit reason={} main_open={} modal={} guard={}",
            reason,
            self.window.is_some() as u8,
            self.dialog_windows.has_modal_window() as u8,
            self.dialog_close_guard_trace()
        );
        event_loop.exit();
    }

    fn drop_windows_for_exit(&mut self) {
        self.renderer = None;
        self.dialog_windows.close_all();
        self.clipboard = None;
        self.window = None;
    }

    fn drain_dialog_window_deferred_closes(&mut self) {
        if self.dialog_windows.drain_ready_deferred_closes() {
            self.request_main_redraw();
        }
    }

    fn open_with_dialog_title(&self) -> String {
        self.scene
            .open_with_chooser
            .as_ref()
            .map(|chooser| format!("Open With - {}", path_name_or_display(&chooser.path)))
            .unwrap_or_else(|| "Open With".to_string())
    }

    fn open_with_dialog_surface_size(&self) -> Option<PhysicalSize<u32>> {
        self.scene
            .open_with_chooser
            .as_ref()
            .map(|chooser| open_with_chooser_window_size_scaled(chooser, self.scene.ui_scale()))
    }

    fn open_with_window_theme(&self) -> Theme {
        if self.scene.theme().is_dark() {
            Theme::Dark
        } else {
            Theme::Light
        }
    }

    fn ensure_dialog_window(
        &mut self,
        event_loop: &dyn ActiveEventLoop,
        kind: ShellDialogWindowKind,
        spec: &ShellDialogWindowSpec,
    ) -> bool {
        if let Some(dialog) = self.dialog_windows.get_mut(kind) {
            dialog.sync(spec);
            return true;
        }
        let dialog = match ShellDetachedDialogWindow::create(
            event_loop,
            self.window.as_deref(),
            self.renderer.as_ref(),
            kind,
            spec,
        ) {
            Ok(dialog) => dialog,
            Err(error) => {
                fika_log!("[fika-wgpu] {error}");
                return false;
            }
        };
        self.dialog_windows.set(kind, dialog);
        self.sync_dialog_window(kind, spec);
        true
    }

    fn sync_dialog_window(&mut self, kind: ShellDialogWindowKind, spec: &ShellDialogWindowSpec) {
        if let Some(dialog) = self.dialog_windows.get_mut(kind) {
            dialog.sync(spec);
        }
    }

    fn close_dialog_window(&mut self, kind: ShellDialogWindowKind) -> bool {
        let closed = self.dialog_windows.close(kind);
        fika_dialog_trace!(
            "[fika-wgpu] dialog-close-dispatch kind={} closed={}",
            kind.as_str(),
            closed as u8
        );
        if closed {
            self.arm_dialog_close_main_close_guard(kind);
        }
        closed
    }

    fn close_dialog_state_and_window(&mut self, kind: ShellDialogWindowKind) -> bool {
        let changed = match kind {
            ShellDialogWindowKind::Create => self.scene.close_create_dialog(),
            ShellDialogWindowKind::OpenWith => self.scene.close_open_with_chooser(),
            ShellDialogWindowKind::Rename => self.scene.close_rename_dialog(),
        };
        let closed = self.close_dialog_window(kind);
        fika_dialog_trace!(
            "[fika-wgpu] dialog-state-close kind={} changed={} closed={}",
            kind.as_str(),
            changed as u8,
            closed as u8
        );
        changed
    }

    fn arm_dialog_close_main_close_guard(&mut self, kind: ShellDialogWindowKind) {
        let deadline = Instant::now() + Duration::from_millis(1_500);
        self.dialog_close_main_close_guard_until = Some(deadline);
        fika_dialog_trace!(
            "[fika-wgpu] dialog-close-guard arm kind={} duration_ms=1500",
            kind.as_str()
        );
    }

    fn close_main_window_from_window_manager_request(
        &mut self,
        event_loop: &dyn ActiveEventLoop,
        reason: &'static str,
    ) {
        let previous_guard = self.dialog_close_guard_trace();
        let modal = self.dialog_windows.has_modal_window();
        self.dialog_close_main_close_guard_until = None;
        fika_dialog_trace!(
            "[fika-wgpu] main-close accept=1 reason={} modal={} previous_guard={}",
            reason,
            modal as u8,
            previous_guard
        );
        self.drop_windows_for_exit();
        self.exit_event_loop(event_loop, reason);
    }

    fn sync_dialog_window_for_kind(&mut self, kind: ShellDialogWindowKind) {
        match kind {
            ShellDialogWindowKind::Create => self.sync_create_dialog_window(),
            ShellDialogWindowKind::OpenWith => self.sync_open_with_dialog_window(),
            ShellDialogWindowKind::Rename => self.sync_rename_dialog_window(),
        }
    }

    fn handle_common_dialog_window_event(
        &mut self,
        kind: ShellDialogWindowKind,
        event: &WindowEvent,
    ) -> bool {
        let Some(event) = self.dialog_windows.handle_window_event(kind, event) else {
            return false;
        };
        fika_dialog_trace!(
            "[fika-wgpu] dialog-host-event kind={} event={:?}",
            kind.as_str(),
            event
        );
        match event {
            ShellDialogWindowHostEvent::CloseRequested => {
                if self.close_dialog_state_and_window(kind) {
                    self.request_main_redraw();
                }
                true
            }
            ShellDialogWindowHostEvent::SurfaceResized => true,
            ShellDialogWindowHostEvent::ScaleFactorChanged {
                scale_factor,
                renderer_size,
            } => {
                let size = self
                    .renderer
                    .as_ref()
                    .map(|renderer| renderer.size)
                    .unwrap_or(renderer_size);
                if self.scene.set_scale_factor(scale_factor, size) {
                    self.request_main_redraw();
                }
                self.sync_dialog_window_for_kind(kind);
                true
            }
            ShellDialogWindowHostEvent::ModifiersChanged(modifiers) => {
                self.modifiers = modifiers;
                true
            }
        }
    }

    fn create_dialog_title(&self) -> String {
        let Some(dialog) = self.scene.create_dialog.as_ref() else {
            return "Create New".to_string();
        };
        if dialog.privileged {
            "Create New as Administrator".to_string()
        } else {
            "Create New".to_string()
        }
    }

    fn create_dialog_spec(&self) -> Option<ShellDialogWindowSpec> {
        self.scene.create_dialog.as_ref()?;
        Some(ShellDialogWindowSpec::fixed(
            self.create_dialog_title(),
            create_dialog_window_size_scaled(self.scene.ui_scale()),
            self.open_with_window_theme(),
        ))
    }

    fn ensure_create_dialog_window(&mut self, event_loop: &dyn ActiveEventLoop) -> bool {
        let Some(spec) = self.create_dialog_spec() else {
            self.close_create_dialog_window();
            return false;
        };
        if !self.ensure_dialog_window(event_loop, ShellDialogWindowKind::Create, &spec) {
            if self.scene.close_create_dialog() {
                self.request_main_redraw();
            }
            return false;
        }
        self.close_rename_dialog_window();
        true
    }

    fn sync_create_dialog_window(&mut self) {
        let Some(spec) = self.create_dialog_spec() else {
            self.close_create_dialog_window();
            return;
        };
        self.sync_dialog_window(ShellDialogWindowKind::Create, &spec);
    }

    fn close_create_dialog_window(&mut self) {
        self.close_dialog_window(ShellDialogWindowKind::Create);
    }

    fn finish_create_dialog_state_change(&mut self) {
        if self.scene.is_create_dialog_open() {
            if self.dialog_windows.is_open(ShellDialogWindowKind::Create) {
                self.sync_create_dialog_window();
            } else {
                if self.scene.close_create_dialog() {
                    self.request_main_redraw();
                }
            }
        } else {
            self.close_create_dialog_window();
            self.request_main_redraw();
        }
    }

    fn rename_dialog_title(&self) -> String {
        let Some(dialog) = self.scene.rename_dialog.as_ref() else {
            return "Rename".to_string();
        };
        match (dialog.is_dir, dialog.privileged) {
            (true, true) => "Rename Folder as Administrator",
            (false, true) => "Rename File as Administrator",
            (true, false) => "Rename Folder",
            (false, false) => "Rename File",
        }
        .to_string()
    }

    fn rename_dialog_spec(&self) -> Option<ShellDialogWindowSpec> {
        self.scene.rename_dialog.as_ref()?;
        Some(ShellDialogWindowSpec::fixed(
            self.rename_dialog_title(),
            rename_dialog_window_size_scaled(self.scene.ui_scale()),
            self.open_with_window_theme(),
        ))
    }

    fn ensure_rename_dialog_window(&mut self, event_loop: &dyn ActiveEventLoop) -> bool {
        let Some(spec) = self.rename_dialog_spec() else {
            self.close_rename_dialog_window();
            return false;
        };
        if !self.ensure_dialog_window(event_loop, ShellDialogWindowKind::Rename, &spec) {
            if self.scene.close_rename_dialog() {
                self.request_main_redraw();
            }
            return false;
        }
        self.close_create_dialog_window();
        true
    }

    fn sync_rename_dialog_window(&mut self) {
        let Some(spec) = self.rename_dialog_spec() else {
            self.close_rename_dialog_window();
            return;
        };
        self.sync_dialog_window(ShellDialogWindowKind::Rename, &spec);
    }

    fn close_rename_dialog_window(&mut self) {
        self.close_dialog_window(ShellDialogWindowKind::Rename);
    }

    fn finish_rename_dialog_state_change(&mut self) {
        if self.scene.is_rename_dialog_open() {
            if self.dialog_windows.is_open(ShellDialogWindowKind::Rename) {
                self.sync_rename_dialog_window();
            } else {
                if self.scene.close_rename_dialog() {
                    self.request_main_redraw();
                }
            }
        } else {
            self.close_rename_dialog_window();
            self.request_main_redraw();
        }
    }

    fn open_with_dialog_spec(&self) -> Option<ShellDialogWindowSpec> {
        Some(ShellDialogWindowSpec::fixed(
            self.open_with_dialog_title(),
            self.open_with_dialog_surface_size()?,
            self.open_with_window_theme(),
        ))
    }

    fn ensure_open_with_dialog_window(&mut self, event_loop: &dyn ActiveEventLoop) -> bool {
        let Some(spec) = self.open_with_dialog_spec() else {
            self.close_open_with_dialog_window();
            return false;
        };
        if !self.ensure_dialog_window(event_loop, ShellDialogWindowKind::OpenWith, &spec) {
            if self.scene.close_open_with_chooser() {
                self.request_main_redraw();
            }
            return false;
        }
        true
    }

    fn sync_open_with_dialog_window(&mut self) {
        let Some(spec) = self.open_with_dialog_spec() else {
            self.close_open_with_dialog_window();
            return;
        };
        self.sync_dialog_window(ShellDialogWindowKind::OpenWith, &spec);
    }

    fn close_open_with_dialog_window(&mut self) {
        self.close_dialog_window(ShellDialogWindowKind::OpenWith);
    }

    fn finish_open_with_dialog_state_change(&mut self) {
        if self.scene.is_open_with_chooser_open() {
            if self.dialog_windows.is_open(ShellDialogWindowKind::OpenWith) {
                self.sync_open_with_dialog_window();
            } else {
                if self.scene.close_open_with_chooser() {
                    self.request_main_redraw();
                }
            }
        } else {
            self.close_open_with_dialog_window();
            self.request_main_redraw();
        }
    }

    fn reconcile_open_with_dialog_lifecycle(&mut self) {
        if !self.dialog_windows.is_open(ShellDialogWindowKind::OpenWith) {
            return;
        }
        if !self.scene.is_open_with_chooser_open() {
            self.close_open_with_dialog_window();
        }
    }

    fn reconcile_dialog_window_lifecycle(&mut self) {
        if self.dialog_windows.is_open(ShellDialogWindowKind::Create) {
            if !self.scene.is_create_dialog_open() {
                self.close_create_dialog_window();
            }
        }
        if self.dialog_windows.is_open(ShellDialogWindowKind::Rename) {
            if !self.scene.is_rename_dialog_open() {
                self.close_rename_dialog_window();
            }
        }
        self.reconcile_open_with_dialog_lifecycle();
    }

    fn drive_directory_watchers(&mut self, event_loop: &dyn ActiveEventLoop) {
        self.directory_watchers.sync_with_scene(&self.scene);
        self.directory_watchers.drain_events(&self.scene);

        let now = Instant::now();
        let reload_paths = self.directory_watchers.take_due_reload_paths(now);
        if reload_paths.is_empty() {
            return;
        }

        let Some(size) = self.renderer.as_ref().map(|renderer| renderer.size) else {
            self.directory_watchers.defer_reload_paths(reload_paths);
            return;
        };

        let mut changed = false;
        for path in reload_paths {
            match self.scene.reload_panes_showing_path(&path, size) {
                Ok(reloaded) => changed |= reloaded,
                Err(error) => {
                    fika_log!(
                        "[fika-wgpu] directory-watch-reload-error path={} error={error}",
                        path.display()
                    );
                }
            }
        }
        self.directory_watchers.sync_with_scene(&self.scene);
        if changed {
            self.present_scene_change(event_loop, "directory-watch");
        }
    }

    fn toggle_user_dark_mode(&mut self) -> bool {
        self.scene.toggle_dark_mode();
        if let Err(error) = save_dark_mode_setting(&self.settings_path, self.scene.dark_mode) {
            fika_log!("[fika-wgpu] settings-save-error {error}");
        }
        if self.dialog_windows.is_open(ShellDialogWindowKind::Create) {
            self.sync_create_dialog_window();
        }
        if self.dialog_windows.is_open(ShellDialogWindowKind::Rename) {
            self.sync_rename_dialog_window();
        }
        if self.dialog_windows.is_open(ShellDialogWindowKind::OpenWith) {
            self.sync_open_with_dialog_window();
        }
        true
    }

    fn next_task_id(&mut self) -> ShellTaskId {
        let task_id = self.next_task_id;
        self.next_task_id = self.next_task_id.saturating_add(1).max(1);
        task_id
    }

    fn drain_async_task_results(&mut self, event_loop: &dyn ActiveEventLoop) {
        let mut changed = false;
        while let Ok(result) = self.async_task_rx.try_recv() {
            match result {
                ShellAsyncTaskResult::Transfer(completion) => {
                    self.active_task_controllers.remove(&completion.task_id);
                    self.active_task_base_details.remove(&completion.task_id);
                    let Some(size) = self.renderer.as_ref().map(|renderer| renderer.size) else {
                        continue;
                    };
                    let clear_clipboard = completion.transfer.result.clear_clipboard
                        && completion.transfer.result.failure_count == 0;
                    let apply_result = self
                        .scene
                        .apply_async_transfer_completion(&completion, size);
                    match apply_result {
                        Ok(result) => {
                            changed = true;
                            if clear_clipboard
                                && result.changed()
                                && let Some(clipboard) = self.clipboard.as_ref()
                                && let Err(error) = clipboard.store_text("")
                            {
                                fika_log!("[fika-wgpu] clipboard-clear-error error={error}");
                            }
                        }
                        Err(error) => {
                            self.scene.record_task_status(ShellTaskStatus::failed(
                                "Task update failed",
                                error,
                                completion.transfer.privileged,
                            ));
                            changed = true;
                        }
                    }
                }
                ShellAsyncTaskResult::TrashView(completion) => {
                    self.active_task_controllers.remove(&completion.task_id);
                    self.active_task_base_details.remove(&completion.task_id);
                    let Some(size) = self.renderer.as_ref().map(|renderer| renderer.size) else {
                        continue;
                    };
                    match self
                        .scene
                        .apply_async_trash_view_completion(&completion, size)
                    {
                        Ok(()) => {
                            changed = true;
                        }
                        Err(error) => {
                            self.scene.finish_task_status(
                                completion.task_id,
                                ShellTaskStatus::failed("Task update failed", error, false),
                            );
                            changed = true;
                        }
                    }
                }
            }
        }
        if changed {
            self.present_scene_change(event_loop, "async-task");
        }
    }

    fn refresh_active_task_progress(&mut self) -> bool {
        let mut changed = false;
        for (task_id, controller) in &self.active_task_controllers {
            let progress = controller.progress();
            if progress.bytes_total == 0 {
                continue;
            }
            let Some(base_detail) = self.active_task_base_details.get(task_id) else {
                continue;
            };
            let percentage = progress
                .bytes_done
                .saturating_mul(100)
                .checked_div(progress.bytes_total)
                .unwrap_or_default()
                .min(100);
            let detail = format!(
                "{} | {} / {} ({}%)",
                base_detail,
                format_size(progress.bytes_done.min(progress.bytes_total)),
                format_size(progress.bytes_total),
                percentage
            );
            changed |= self.scene.update_running_task_detail(*task_id, detail);
        }
        changed
    }

    fn autosmoke_work_pending(&self) -> bool {
        !self.autosmoke_zoom_actions.is_empty()
            || !self.autosmoke_scroll_actions.is_empty()
            || self
                .dialog_lifecycle_smoke
                .is_some_and(DialogLifecycleSmoke::pending)
    }

    fn drive_autosmoke_after_render(&mut self) {
        let Some((size, frame_count)) = self
            .renderer
            .as_ref()
            .map(|renderer| (renderer.size, renderer.frame_count))
        else {
            return;
        };
        if frame_count == 0 {
            return;
        }
        self.drive_autosmoke_zoom(size);
        self.drive_autosmoke_scroll(size);
        if self.autosmoke_work_pending()
            && let Some(window) = self.window.as_ref()
        {
            window.request_redraw();
        }
    }

    fn drive_dialog_lifecycle_autosmoke(&mut self, event_loop: &dyn ActiveEventLoop) {
        let Some(smoke_state) = self.dialog_lifecycle_smoke else {
            return;
        };
        let kind = smoke_state.kind;
        match smoke_state.step {
            DialogLifecycleSmokeStep::WaitMainFrame => {
                let Some(frame_count) = self.renderer.as_ref().map(|renderer| renderer.frame_count)
                else {
                    return;
                };
                if frame_count == 0 {
                    return;
                }
                if !self.open_dialog_for_autosmoke(kind) {
                    self.finish_dialog_lifecycle_autosmoke(false, event_loop);
                    return;
                }
                if !self.ensure_dialog_window_for_autosmoke_kind(kind, event_loop) {
                    self.finish_dialog_lifecycle_autosmoke(false, event_loop);
                    return;
                }
                fika_log!(
                    "[fika-wgpu] dialog-smoke open kind={} main_frame={}",
                    kind.as_str(),
                    frame_count
                );
                if let Some(smoke) = self.dialog_lifecycle_smoke.as_mut() {
                    smoke.step = DialogLifecycleSmokeStep::WaitDialogFrame;
                }
                self.request_dialog_redraw(kind);
            }
            DialogLifecycleSmokeStep::WaitDialogFrame => {
                let frame_count = self.dialog_windows.frame_count(kind).unwrap_or(0);
                if frame_count == 0 {
                    self.request_dialog_redraw(kind);
                    return;
                }
                let close_frame = self
                    .renderer
                    .as_ref()
                    .map(|renderer| renderer.frame_count)
                    .unwrap_or(0);
                fika_log!(
                    "[fika-wgpu] dialog-smoke close kind={} dialog_frame={} main_frame={}",
                    kind.as_str(),
                    frame_count,
                    close_frame
                );
                self.handle_common_dialog_window_event(kind, &WindowEvent::CloseRequested);
                if let Some(smoke) = self.dialog_lifecycle_smoke.as_mut() {
                    smoke.step = DialogLifecycleSmokeStep::WaitMainFrameAfterClose;
                    smoke.close_frame = close_frame;
                }
                self.request_main_redraw();
            }
            DialogLifecycleSmokeStep::WaitMainFrameAfterClose => {
                let Some(smoke) = self.dialog_lifecycle_smoke else {
                    return;
                };
                let Some(frame_count) = self.renderer.as_ref().map(|renderer| renderer.frame_count)
                else {
                    self.finish_dialog_lifecycle_autosmoke(false, event_loop);
                    return;
                };
                if self.dialog_windows.has_modal_window() || frame_count < smoke.close_frame {
                    self.request_main_redraw();
                    return;
                }
                if smoke.cycles_remaining > 1 {
                    if let Some(smoke) = self.dialog_lifecycle_smoke.as_mut() {
                        smoke.cycles_remaining -= 1;
                        smoke.step = DialogLifecycleSmokeStep::WaitMainFrame;
                    }
                    self.request_main_redraw();
                    return;
                }
                self.finish_dialog_lifecycle_autosmoke(true, event_loop);
            }
            DialogLifecycleSmokeStep::Complete | DialogLifecycleSmokeStep::Failed => {}
        }
    }

    fn open_dialog_for_autosmoke(&mut self, kind: ShellDialogWindowKind) -> bool {
        match kind {
            ShellDialogWindowKind::Create => self.scene.open_create_dialog_for_autosmoke(),
            ShellDialogWindowKind::OpenWith => self
                .scene
                .open_open_with_chooser_for_autosmoke(&self.mime_applications),
            ShellDialogWindowKind::Rename => self.scene.open_rename_dialog_for_autosmoke(),
        }
    }

    fn ensure_dialog_window_for_autosmoke_kind(
        &mut self,
        kind: ShellDialogWindowKind,
        event_loop: &dyn ActiveEventLoop,
    ) -> bool {
        match kind {
            ShellDialogWindowKind::Create => self.ensure_create_dialog_window(event_loop),
            ShellDialogWindowKind::OpenWith => self.ensure_open_with_dialog_window(event_loop),
            ShellDialogWindowKind::Rename => self.ensure_rename_dialog_window(event_loop),
        }
    }

    fn finish_dialog_lifecycle_autosmoke(
        &mut self,
        success: bool,
        event_loop: &dyn ActiveEventLoop,
    ) {
        let Some(()) = self.dialog_lifecycle_smoke.as_mut().map(|smoke| {
            smoke.step = if success {
                DialogLifecycleSmokeStep::Complete
            } else {
                DialogLifecycleSmokeStep::Failed
            };
            event_loop.set_control_flow(ControlFlow::Wait);
        }) else {
            return;
        };
        fika_log!(
            "[fika-wgpu] dialog-smoke {} main_open={} modal={} guard={}",
            if success { "complete" } else { "failed" },
            self.window.is_some() as u8,
            self.dialog_windows.has_modal_window() as u8,
            self.dialog_close_guard_trace()
        );
    }

    fn drive_autosmoke_zoom(&mut self, size: PhysicalSize<u32>) {
        if !(self.autosmoke_zoom_allow_pending_redraw || self.pending_redraw_frames == 0)
            || Instant::now() < self.next_autosmoke_zoom
        {
            return;
        }
        let Some(action) = self.autosmoke_zoom_actions.pop_front() else {
            return;
        };
        if self.scene.zoom(action, size) {
            fika_log!("[fika-wgpu] autosmoke-zoom action={}", action.as_str());
            self.next_autosmoke_zoom = Instant::now() + self.autosmoke_zoom_interval;
            self.queue_scene_change("autosmoke-zoom", ZOOM_REDRAW_FRAMES);
        } else {
            self.next_autosmoke_zoom = Instant::now() + self.autosmoke_zoom_interval;
        }
    }

    fn drive_autosmoke_scroll(&mut self, size: PhysicalSize<u32>) {
        if !(self.autosmoke_scroll_allow_pending_redraw || self.pending_redraw_frames == 0)
            || Instant::now() < self.next_autosmoke_scroll
        {
            return;
        }
        while let Some(action) = self.autosmoke_scroll_actions.pop_front() {
            let old_x = self.scene.panes[ShellPaneId::SLOT_0].scroll_x;
            let old_y = self.scene.panes[ShellPaneId::SLOT_0].scroll_y;
            let changed = self.scene.scroll_by(action.delta, size);
            let new_x = self.scene.panes[ShellPaneId::SLOT_0].scroll_x;
            let new_y = self.scene.panes[ShellPaneId::SLOT_0].scroll_y;
            fika_log!(
                "[fika-wgpu] autosmoke-scroll action={} delta={:.1} changed={} old_scroll_x={:.1} new_scroll_x={:.1} old_scroll_y={:.1} new_scroll_y={:.1}",
                action.label,
                action.delta,
                changed as u8,
                old_x,
                new_x,
                old_y,
                new_y
            );
            self.next_autosmoke_scroll = Instant::now() + self.autosmoke_scroll_interval;
            if changed {
                self.queue_scene_change("autosmoke-scroll", SCROLL_REDRAW_FRAMES);
                break;
            }
        }
    }

    fn cancel_task_if_running(&mut self, task_id: ShellTaskId) {
        if let Some(controller) = self.active_task_controllers.get(&task_id) {
            controller.cancel();
        }
    }

    fn start_async_transfer(
        &mut self,
        source: ShellAsyncTransferSource,
        target_dir: PathBuf,
        mode: FileTransferMode,
        paths: Vec<PathBuf>,
        label: &'static str,
        clear_clipboard: bool,
    ) {
        let task_id = self.next_task_id();
        let controller = OperationController::new();
        self.active_task_controllers
            .insert(task_id, controller.clone());
        let base_detail = async_transfer_task_detail(&target_dir, paths.len(), clear_clipboard);
        self.active_task_base_details
            .insert(task_id, base_detail.clone());
        self.scene.record_async_transfer_started(
            task_id,
            source,
            mode,
            &target_dir,
            paths.len(),
            clear_clipboard,
            base_detail,
        );
        let tx = self.async_task_tx.clone();
        thread::spawn(move || {
            let transfer = pollster::block_on(run_operation_task({
                let controller = controller.clone();
                let target_dir = target_dir.clone();
                let paths = paths.clone();
                move || async move {
                    transfer_paths_async_with_controller(
                        target_dir,
                        mode,
                        paths,
                        label,
                        clear_clipboard,
                        controller,
                    )
                    .await
                }
            }))
            .unwrap_or_else(|error| {
                transfer_runtime_failure(target_dir.clone(), mode, label, clear_clipboard, error)
            });
            let _ = tx.send(ShellAsyncTaskResult::Transfer(
                ShellAsyncTransferCompletion {
                    task_id,
                    source,
                    target_dir,
                    transfer,
                },
            ));
        });
    }

    fn start_async_trash_view_operation(
        &mut self,
        action: ShellContextMenuAction,
    ) -> Result<(), String> {
        let pane_to_reload = self
            .scene
            .context_target_pane()
            .unwrap_or_else(|| self.scene.active_pane());
        let (operation, paths) = self.scene.context_target_trash_view_operation(action)?;
        let task_id = self.next_task_id();
        self.active_task_controllers
            .insert(task_id, OperationController::new());
        self.scene
            .record_async_trash_view_started(task_id, operation, paths.len());

        let tx = self.async_task_tx.clone();
        thread::spawn(move || {
            let result = pollster::block_on(run_operation_task({
                let paths = paths;
                move || async move {
                    trash_view_operation_result_async(WGPU_SHELL_PANE_ID, operation, paths).await
                }
            }))
            .unwrap_or_else(|error| {
                fika_log!(
                    "[fika-wgpu] trash-view-runtime-error action={} {error}",
                    action.as_str()
                );
                trash_view_operation_runtime_failure(operation)
            });
            let _ = tx.send(ShellAsyncTaskResult::TrashView(
                ShellAsyncTrashViewCompletion {
                    task_id,
                    action,
                    pane_to_reload,
                    result,
                },
            ));
        });
        Ok(())
    }

    fn create_dialog_window_event(&mut self, event_loop: &dyn ActiveEventLoop, event: WindowEvent) {
        if self.handle_common_dialog_window_event(ShellDialogWindowKind::Create, &event) {
            return;
        }
        match event {
            WindowEvent::KeyboardInput {
                event,
                is_synthetic: false,
                ..
            } => {
                if event.state != ElementState::Pressed {
                    return;
                }
                let size = self
                    .dialog_windows
                    .layout_size(ShellDialogWindowKind::Create)
                    .unwrap_or_else(|| PhysicalSize::new(1, 1));
                let shortcut =
                    self.modifiers.state().control_key() || self.modifiers.state().meta_key();
                match create_command_for_key_event(&event, shortcut) {
                    CreateCommand::Commit => self.commit_create_dialog(event_loop),
                    CreateCommand::Ignore => {}
                    command => {
                        if self.scene.apply_create_command(command, size) {
                            self.finish_create_dialog_state_change();
                        }
                    }
                }
            }
            WindowEvent::PointerMoved { .. } | WindowEvent::PointerLeft { .. } => {
                self.dialog_windows
                    .set_cursor(ShellDialogWindowKind::Create, CursorIcon::Default);
            }
            WindowEvent::PointerButton {
                state,
                position,
                button,
                ..
            } => {
                if state != ElementState::Pressed {
                    return;
                }
                let Some(mouse_button) = button.mouse_button() else {
                    return;
                };
                if mouse_button != MouseButton::Left {
                    return;
                }
                let Some(size) = self
                    .dialog_windows
                    .layout_size(ShellDialogWindowKind::Create)
                else {
                    return;
                };
                let point = ViewPoint {
                    x: position.x as f32,
                    y: position.y as f32,
                };
                match self.scene.create_dialog_click_at_screen_point(point, size) {
                    CreateDialogClick::Outside | CreateDialogClick::Cancel => {
                        if self.close_dialog_state_and_window(ShellDialogWindowKind::Create) {
                            self.request_main_redraw();
                        }
                    }
                    CreateDialogClick::Commit => self.commit_create_dialog(event_loop),
                    CreateDialogClick::Kind(kind) => {
                        if self
                            .scene
                            .apply_create_command(CreateCommand::SetKind(kind), size)
                        {
                            self.finish_create_dialog_state_change();
                        }
                    }
                    CreateDialogClick::Inside => {}
                }
            }
            WindowEvent::RedrawRequested => {
                self.render_create_dialog_now(event_loop, "create-dialog-redraw");
            }
            _ => {}
        }
    }

    fn rename_dialog_window_event(&mut self, event_loop: &dyn ActiveEventLoop, event: WindowEvent) {
        if self.handle_common_dialog_window_event(ShellDialogWindowKind::Rename, &event) {
            return;
        }
        match event {
            WindowEvent::KeyboardInput {
                event,
                is_synthetic: false,
                ..
            } => {
                if event.state != ElementState::Pressed {
                    return;
                }
                let shortcut =
                    self.modifiers.state().control_key() || self.modifiers.state().meta_key();
                match rename_command_for_key_event(&event, shortcut) {
                    RenameCommand::Commit => self.commit_rename_dialog(event_loop),
                    RenameCommand::Ignore => {}
                    command => {
                        if self.scene.apply_rename_command(command) {
                            self.finish_rename_dialog_state_change();
                        }
                    }
                }
            }
            WindowEvent::PointerMoved { .. } | WindowEvent::PointerLeft { .. } => {
                self.dialog_windows
                    .set_cursor(ShellDialogWindowKind::Rename, CursorIcon::Default);
            }
            WindowEvent::PointerButton {
                state,
                position,
                button,
                ..
            } => {
                if state != ElementState::Pressed {
                    return;
                }
                let Some(mouse_button) = button.mouse_button() else {
                    return;
                };
                if mouse_button != MouseButton::Left {
                    return;
                }
                let Some(size) = self
                    .dialog_windows
                    .layout_size(ShellDialogWindowKind::Rename)
                else {
                    return;
                };
                let point = ViewPoint {
                    x: position.x as f32,
                    y: position.y as f32,
                };
                match self.scene.rename_dialog_click_at_screen_point(point, size) {
                    RenameDialogClick::Outside | RenameDialogClick::Cancel => {
                        if self.close_dialog_state_and_window(ShellDialogWindowKind::Rename) {
                            self.request_main_redraw();
                        }
                    }
                    RenameDialogClick::Commit => self.commit_rename_dialog(event_loop),
                    RenameDialogClick::Inside => {}
                }
            }
            WindowEvent::RedrawRequested => {
                self.render_rename_dialog_now(event_loop, "rename-dialog-redraw");
            }
            _ => {}
        }
    }

    fn open_with_dialog_window_event(
        &mut self,
        event_loop: &dyn ActiveEventLoop,
        event: WindowEvent,
    ) {
        if self.handle_common_dialog_window_event(ShellDialogWindowKind::OpenWith, &event) {
            return;
        }
        match event {
            WindowEvent::KeyboardInput {
                event,
                is_synthetic: false,
                ..
            } => {
                if event.state != ElementState::Pressed {
                    return;
                }
                let shortcut =
                    self.modifiers.state().control_key() || self.modifiers.state().meta_key();
                match open_with_command_for_key_event(&event, shortcut) {
                    OpenWithCommand::Commit => self.commit_open_with_chooser(),
                    OpenWithCommand::Ignore => {}
                    command => {
                        if self.scene.apply_open_with_command(command) {
                            self.finish_open_with_dialog_state_change();
                        }
                    }
                }
            }
            WindowEvent::PointerMoved { position, .. } => {
                let Some(size) = self
                    .dialog_windows
                    .layout_size(ShellDialogWindowKind::OpenWith)
                else {
                    return;
                };
                let point = ViewPoint {
                    x: position.x as f32,
                    y: position.y as f32,
                };
                let changed = self.scene.set_pointer(point, size);
                self.update_open_with_dialog_cursor_for_scene(size);
                if changed {
                    self.request_open_with_dialog_redraw();
                }
            }
            WindowEvent::PointerLeft { .. } => {
                self.set_open_with_dialog_cursor(CursorIcon::Default);
                if self.scene.clear_pointer() {
                    self.request_open_with_dialog_redraw();
                }
            }
            WindowEvent::PointerButton {
                state,
                position,
                button,
                ..
            } => {
                let Some(size) = self
                    .dialog_windows
                    .layout_size(ShellDialogWindowKind::OpenWith)
                else {
                    return;
                };
                let point = ViewPoint {
                    x: position.x as f32,
                    y: position.y as f32,
                };
                let Some(mouse_button) = button.mouse_button() else {
                    return;
                };
                if state == ElementState::Released && self.scene.is_scrollbar_dragging() {
                    let changed = self.scene.end_scrollbar_drag(point, size);
                    self.set_open_with_dialog_cursor(CursorIcon::Default);
                    if changed {
                        self.request_open_with_dialog_redraw();
                    }
                    return;
                }
                if state == ElementState::Pressed && mouse_button == MouseButton::Left {
                    if let Some(changed) = self.scene.begin_open_with_scrollbar_drag(point, size) {
                        self.set_open_with_dialog_cursor(CursorIcon::Default);
                        if changed {
                            self.request_open_with_dialog_redraw();
                        }
                        return;
                    }
                    match self
                        .scene
                        .open_with_chooser_click_at_screen_point(point, size)
                    {
                        OpenWithChooserClick::Outside | OpenWithChooserClick::Cancel => {
                            if self.close_dialog_state_and_window(ShellDialogWindowKind::OpenWith) {
                                self.request_main_redraw();
                            }
                        }
                        OpenWithChooserClick::Open => self.commit_open_with_chooser(),
                        OpenWithChooserClick::ToggleDefault => {
                            if self.scene.toggle_open_with_set_default() {
                                self.finish_open_with_dialog_state_change();
                            }
                        }
                        OpenWithChooserClick::Query(cursor) => {
                            if self.scene.set_open_with_query_cursor(cursor) {
                                self.finish_open_with_dialog_state_change();
                            }
                        }
                        OpenWithChooserClick::Row(row) => {
                            if self.scene.select_open_with_filtered_row(row) {
                                self.finish_open_with_dialog_state_change();
                            }
                        }
                        OpenWithChooserClick::Inside => {}
                    }
                }
            }
            WindowEvent::MouseWheel { delta, .. } => {
                let delta_y = scroll_delta_y(delta, self.scene.ui_scale());
                if self.scene.scroll_open_with_chooser_by(delta_y) {
                    self.request_open_with_dialog_redraw();
                }
            }
            WindowEvent::RedrawRequested => {
                self.render_open_with_dialog_now(event_loop, "open-with-dialog-redraw");
            }
            _ => {}
        }
    }
}

impl ApplicationHandler for FikaWgpuApp {
    fn proxy_wake_up(&mut self, event_loop: &dyn ActiveEventLoop) {
        self.drive_directory_watchers(event_loop);
        if let Some(deadline) = self.directory_watchers.next_reload_deadline() {
            event_loop.set_control_flow(ControlFlow::WaitUntil(deadline));
        }
    }

    fn can_create_surfaces(&mut self, event_loop: &dyn ActiveEventLoop) {
        if self.window.is_some() {
            return;
        }

        let attrs = WindowAttributes::default()
            .with_title(window_title(&self.scene))
            .with_surface_size(PhysicalSize::new(1100, 720));
        let attrs = apply_window_platform_semantics(event_loop, attrs, ShellWindowRole::Main);

        let window = match event_loop.create_window(attrs) {
            Ok(window) => window,
            Err(error) => {
                fika_log!("[fika-wgpu] window create failed: {error}");
                self.exit_event_loop(event_loop, "main-window-create-failed");
                return;
            }
        };

        let window: Arc<dyn Window> = window.into();
        let mut renderer = match WgpuState::new(window.clone()) {
            Ok(renderer) => renderer,
            Err(error) => {
                fika_log!("[fika-wgpu] renderer init failed: {error}");
                self.exit_event_loop(event_loop, "main-renderer-init-failed");
                return;
            }
        };
        let clipboard = match ShellClipboard::from_window(window.as_ref()) {
            Ok(Some(clipboard)) => {
                fika_log!(
                    "[fika-wgpu] clipboard-ready backend={}",
                    clipboard.backend()
                );
                Some(clipboard)
            }
            Ok(None) => {
                fika_log!("[fika-wgpu] clipboard-unavailable backend=unsupported");
                None
            }
            Err(error) => {
                fika_log!("[fika-wgpu] clipboard-unavailable error={error}");
                None
            }
        };

        self.scene
            .set_scale_factor(window.scale_factor() as f32, renderer.size);

        fika_log!(
            "[fika-wgpu] shell-ready size={}x{} scale={:.2}",
            renderer.size.width,
            renderer.size.height,
            window.scale_factor()
        );

        self.scene.clamp_scroll(renderer.size);
        renderer.prewarm_scene_caches(&mut self.scene, "startup");
        self.renderer = Some(renderer);
        self.clipboard = clipboard;
        self.window = Some(window);

        if let Some(window) = self.window.as_ref() {
            window.request_redraw();
        }
    }

    fn about_to_wait(&mut self, event_loop: &dyn ActiveEventLoop) {
        self.drive_directory_watchers(event_loop);
        self.drain_async_task_results(event_loop);
        let progress_changed = self.refresh_active_task_progress();
        let animation_pruned = self.scene.prune_finished_animations();
        if (progress_changed || animation_pruned)
            && let Some(window) = self.window.as_ref()
        {
            window.request_redraw();
        }
        if self.auto_cycle_views && Instant::now() >= self.next_auto_cycle {
            self.next_auto_cycle = Instant::now() + AUTO_CYCLE_INTERVAL;
            if let Some(renderer) = self.renderer.as_ref() {
                let next = self.scene.active_view_mode().next();
                if self.scene.set_view_mode(next, renderer.size) {
                    self.pending_redraw_frames = VIEW_SWITCH_REDRAW_FRAMES;
                    if let Some(window) = self.window.as_ref() {
                        window.set_title(&window_title(&self.scene));
                        window.request_redraw();
                    }
                    self.prewarm_current_scene_caches("auto-cycle");
                    self.render_now(event_loop, "auto-cycle", true);
                }
            }
        }
        if let Some(renderer) = self.renderer.as_ref()
            && renderer.frame_count > 0
        {
            let size = renderer.size;
            self.drive_autosmoke_zoom(size);
            self.drive_autosmoke_scroll(size);
        }
        self.drive_dialog_lifecycle_autosmoke(event_loop);
        self.drain_dialog_window_deferred_closes();

        let autosmoke_work_pending = self.autosmoke_work_pending();
        let animation_active = self.scene.animation_active();
        let next_text_caret_deadline = self.scene.next_text_caret_blink_deadline();
        let location_caret_active = self.scene.location_text_caret_active();
        let location_caret_dirty_value = self.scene.location_text_caret_dirty_value();
        let location_caret_blink_due = location_caret_active
            && location_caret_dirty_value != self.last_location_text_caret_dirty_value;
        self.last_location_text_caret_dirty_value = if location_caret_active {
            location_caret_dirty_value
        } else {
            0
        };
        let open_with_caret_active = self.scene.open_with_text_caret_active();
        let open_with_caret_dirty_value = self.scene.open_with_text_caret_dirty_value();
        let open_with_caret_blink_due = open_with_caret_active
            && open_with_caret_dirty_value != self.last_open_with_text_caret_dirty_value;
        self.last_open_with_text_caret_dirty_value = if open_with_caret_active {
            open_with_caret_dirty_value
        } else {
            0
        };
        let dialog_redraw_requested =
            open_with_caret_blink_due && self.request_open_with_dialog_redraw();
        let needs_redraw = self.renderer.as_ref().is_some_and(|renderer| {
            renderer.frame_count == 0
                || renderer.rendered_view_switches != self.scene.view_switches
                || self.pending_redraw_frames > 0
                || animation_active
                || location_caret_blink_due
                || (autosmoke_work_pending && renderer.frame_count > 0)
        });
        let next_autosmoke_deadline = [
            (!self.autosmoke_zoom_actions.is_empty()).then_some(self.next_autosmoke_zoom),
            (!self.autosmoke_scroll_actions.is_empty()).then_some(self.next_autosmoke_scroll),
        ]
        .into_iter()
        .flatten()
        .min();
        let next_idle_deadline = [
            self.auto_cycle_views.then_some(self.next_auto_cycle),
            next_autosmoke_deadline,
            self.dialog_windows.next_deferred_close_deadline(),
            self.scene.next_animation_frame_deadline(),
            next_text_caret_deadline,
            self.directory_watchers.next_reload_deadline(),
        ]
        .into_iter()
        .flatten()
        .min();

        if needs_redraw && let Some(window) = self.window.as_ref() {
            window.request_redraw();
        }

        if needs_redraw || dialog_redraw_requested {
            event_loop.set_control_flow(ControlFlow::Poll);
        } else if !self.active_task_controllers.is_empty() {
            event_loop.set_control_flow(ControlFlow::WaitUntil(
                Instant::now() + Duration::from_millis(100),
            ));
        } else if let Some(deadline) = next_idle_deadline {
            event_loop.set_control_flow(ControlFlow::WaitUntil(deadline));
        } else {
            event_loop.set_control_flow(ControlFlow::Wait);
        }
    }

    fn window_event(
        &mut self,
        event_loop: &dyn ActiveEventLoop,
        window_id: WindowId,
        event: WindowEvent,
    ) {
        self.trace_window_event(window_id, &event);
        if let Some(kind) = self.dialog_windows.window_kind_for_id(window_id) {
            match kind {
                ShellDialogWindowKind::Create => {
                    self.create_dialog_window_event(event_loop, event);
                    return;
                }
                ShellDialogWindowKind::OpenWith => {
                    self.open_with_dialog_window_event(event_loop, event);
                    return;
                }
                ShellDialogWindowKind::Rename => {
                    self.rename_dialog_window_event(event_loop, event);
                    return;
                }
            }
        }
        if self.dialog_windows.is_recently_closed_window(window_id) {
            if matches!(event, WindowEvent::CloseRequested)
                && window_manager_close_request_exits_application(
                    ShellWindowCloseRequestTarget::RecentlyClosedDialog,
                    self.dialog_windows.has_modal_window(),
                )
                && self.window.is_some()
            {
                self.close_main_window_from_window_manager_request(
                    event_loop,
                    "recently-closed-dialog-close-requested",
                );
            }
            return;
        }
        let Some(main_window_id) = self.window.as_ref().map(|window| window.id()) else {
            return;
        };
        if main_window_id != window_id {
            return;
        }
        let modal_disposition = self.dialog_windows.modal_event_disposition(&event);
        if modal_disposition.blocks() {
            if modal_disposition.requests_attention() {
                self.dialog_windows.request_modal_attention();
            }
            return;
        }
        match event {
            WindowEvent::CloseRequested => {
                if window_manager_close_request_exits_application(
                    ShellWindowCloseRequestTarget::Main,
                    self.dialog_windows.has_modal_window(),
                ) {
                    self.close_main_window_from_window_manager_request(
                        event_loop,
                        "main-close-requested",
                    );
                }
            }
            WindowEvent::SurfaceResized(size) => {
                if let Some(renderer) = self.renderer.as_mut() {
                    renderer.resize(size);
                    self.scene.clamp_scroll(renderer.size);
                }
                if let Some(window) = self.window.as_ref() {
                    window.request_redraw();
                }
            }
            WindowEvent::ScaleFactorChanged { .. } => {
                if let (Some(renderer), Some(window)) =
                    (self.renderer.as_mut(), self.window.as_ref())
                {
                    renderer.resize(window.surface_size());
                    self.scene
                        .set_scale_factor(window.scale_factor() as f32, renderer.size);
                    window.request_redraw();
                }
            }
            WindowEvent::ModifiersChanged(modifiers) => {
                self.modifiers = modifiers;
            }
            WindowEvent::KeyboardInput {
                event,
                is_synthetic: false,
                ..
            } => {
                self.handle_main_keyboard_input(event_loop, &event);
            }
            WindowEvent::PointerMoved { position, .. } => {
                self.handle_main_pointer_moved(position);
            }
            WindowEvent::PointerLeft { .. } => {
                self.handle_main_pointer_left();
            }
            WindowEvent::DragEntered { paths, position } => {
                let outcome = self.external_drag_entered(paths, position);
                self.apply_window_action_outcome(outcome);
            }
            WindowEvent::DragMoved { position } => {
                let outcome = self.external_drag_moved(position);
                self.apply_window_action_outcome(outcome);
            }
            WindowEvent::DragDropped { paths, position } => {
                let outcome = self.external_drag_dropped(paths, position);
                self.apply_window_action_outcome(outcome);
            }
            WindowEvent::DragLeft { .. } => {
                let outcome = self.external_drag_left();
                self.apply_window_action_outcome(outcome);
            }
            WindowEvent::PointerButton {
                state,
                position,
                button,
                ..
            } => {
                self.handle_main_pointer_button(event_loop, state, position, button);
            }
            WindowEvent::MouseWheel { delta, .. } => {
                self.handle_main_mouse_wheel(delta);
            }
            WindowEvent::RedrawRequested => {
                let force_log = self.pending_redraw_frames > 0;
                let reason = self.pending_render_reason.take().unwrap_or(if force_log {
                    "switch-redraw"
                } else {
                    "redraw"
                });
                self.render_now(event_loop, reason, force_log);
            }
            _ => {}
        }
    }
}

impl FikaWgpuApp {
    fn queue_scene_change(&mut self, reason: &'static str, redraw_frames: u8) {
        self.pending_redraw_frames = self.pending_redraw_frames.max(redraw_frames);
        self.pending_render_reason = Some(reason);
        if let Some(window) = self.window.as_ref() {
            window.set_title(&window_title(&self.scene));
            window.request_redraw();
        }
    }

    fn present_scene_change(&mut self, event_loop: &dyn ActiveEventLoop, reason: &'static str) {
        self.pending_redraw_frames = VIEW_SWITCH_REDRAW_FRAMES;
        self.pending_render_reason = None;
        if let Some(window) = self.window.as_ref() {
            window.set_title(&window_title(&self.scene));
            window.request_redraw();
        }
        self.prewarm_current_scene_caches(reason);
        self.render_now(event_loop, reason, true);
    }

    fn prewarm_current_scene_caches(&mut self, reason: &'static str) {
        let Some(renderer) = self.renderer.as_mut() else {
            return;
        };
        renderer.prewarm_scene_caches(&mut self.scene, reason);
    }

    fn render_create_dialog_now(&mut self, event_loop: &dyn ActiveEventLoop, reason: &'static str) {
        let Some(dialog_state) = self.scene.create_dialog.as_ref() else {
            self.close_create_dialog_window();
            return;
        };
        let scale = self.scene.ui_scale();
        let popup_theme = PopupTheme::from_shell_theme(self.scene.theme());
        let Some(dialog_window) = self.dialog_windows.get_mut(ShellDialogWindowKind::Create) else {
            return;
        };
        let layout_size = dialog_window.layout_size();
        let (renderer, window) = dialog_window.renderer_and_window_mut();
        renderer.render_create_dialog(
            window,
            event_loop,
            dialog_state,
            popup_theme,
            scale,
            layout_size,
            reason,
        );
    }

    fn render_rename_dialog_now(&mut self, event_loop: &dyn ActiveEventLoop, reason: &'static str) {
        let Some(dialog_state) = self.scene.rename_dialog.as_ref() else {
            self.close_rename_dialog_window();
            return;
        };
        let scale = self.scene.ui_scale();
        let popup_theme = PopupTheme::from_shell_theme(self.scene.theme());
        let Some(dialog_window) = self.dialog_windows.get_mut(ShellDialogWindowKind::Rename) else {
            return;
        };
        let layout_size = dialog_window.layout_size();
        let (renderer, window) = dialog_window.renderer_and_window_mut();
        renderer.render_rename_dialog(
            window,
            event_loop,
            dialog_state,
            popup_theme,
            scale,
            layout_size,
            reason,
        );
    }

    fn render_open_with_dialog_now(
        &mut self,
        event_loop: &dyn ActiveEventLoop,
        reason: &'static str,
    ) {
        let Some(chooser) = self.scene.open_with_chooser.as_ref() else {
            self.close_open_with_dialog_window();
            return;
        };
        let scale = self.scene.ui_scale();
        let caret_visible = self.scene.text_caret_visible();
        let popup_theme = PopupTheme::from_shell_theme(self.scene.theme());
        let Some(dialog) = self.dialog_windows.get_mut(ShellDialogWindowKind::OpenWith) else {
            return;
        };
        let layout_size = dialog.layout_size();
        let (renderer, window) = dialog.renderer_and_window_mut();
        renderer.render_open_with_dialog(
            window,
            event_loop,
            chooser,
            popup_theme,
            scale,
            layout_size,
            caret_visible,
            reason,
        );
    }

    fn render_now(
        &mut self,
        event_loop: &dyn ActiveEventLoop,
        reason: &'static str,
        force_log: bool,
    ) {
        self.reconcile_dialog_window_lifecycle();
        let rendered = {
            let Some(window) = self.window.as_ref() else {
                return;
            };
            let Some(renderer) = self.renderer.as_mut() else {
                return;
            };

            renderer.render(
                window.as_ref(),
                event_loop,
                &mut self.scene,
                reason,
                force_log,
            )
        };

        if rendered.consumed_redraw_request() && self.pending_redraw_frames > 0 {
            self.pending_redraw_frames -= 1;
        }
        if rendered.presented() {
            self.drive_autosmoke_after_render();
        }
    }
}

fn scroll_delta_y(delta: MouseScrollDelta, scale_factor: f32) -> f32 {
    match delta {
        MouseScrollDelta::LineDelta(_, y) => -y * SCROLL_LINE_PX * scale_factor,
        MouseScrollDelta::PixelDelta(position) => -position.y as f32,
    }
}

