#[derive(Clone, Debug, Eq, PartialEq)]
struct ShellPlace {
    group: &'static str,
    marker: &'static str,
    icon_name: &'static str,
    label: String,
    path: PathBuf,
    device: Option<ShellDevicePlace>,
    network: bool,
    trash: bool,
    root: bool,
    editable: bool,
}

impl ShellPlace {
    fn new(
        group: &'static str,
        marker: &'static str,
        label: impl Into<String>,
        path: PathBuf,
        editable: bool,
    ) -> Self {
        let trash = file_ops::is_trash_files_dir(&path);
        let network = is_network_path(&path);
        let root = path == PathBuf::from("/");
        let icon_name = shell_place_icon_name(marker, trash, network, root, editable);
        Self {
            group,
            marker,
            icon_name,
            label: label.into(),
            path,
            device: None,
            network,
            trash,
            root,
            editable,
        }
    }

    fn with_device(mut self, device: ShellDevicePlace) -> Self {
        self.icon_name = "drive-removable-media";
        self.device = Some(device);
        self
    }
}

fn place_icon_paint(place: &ShellPlace, active: bool) -> PlaceIconPaint {
    PlaceIconPaint::from_flags(
        active,
        place.trash,
        place.network,
        place.root,
        place.editable,
        place.marker == "D" || place.marker == "/",
    )
}

fn shell_place_icon_name(
    marker: &str,
    trash: bool,
    network: bool,
    root: bool,
    editable: bool,
) -> &'static str {
    if trash {
        return "user-trash";
    }
    if network {
        return "folder-remote";
    }
    if root {
        return "drive-harddisk";
    }
    match marker {
        "H" => "user-home",
        "Desk" => "user-desktop",
        "Doc" => "folder-documents",
        "Down" => "folder-download",
        "Mus" => "folder-music",
        "Pic" => "folder-pictures",
        "Vid" => "folder-videos",
        "D" => "drive-removable-media",
        "/" => "drive-harddisk",
        _ if editable => "folder-bookmark",
        _ => "folder",
    }
}

