    fn reload_panes_showing_path(
        &mut self,
        path: &Path,
        size: PhysicalSize<u32>,
    ) -> Result<bool, String> {
        let pane_ids = ShellPaneId::ALL
            .into_iter()
            .filter(|pane| {
                self.pane_state(*pane)
                    .is_some_and(|state| same_directory(&state.path, path))
            })
            .collect::<Vec<_>>();
        let mut changed = false;
        for pane in pane_ids {
            changed |= self.reload_pane_path(pane, size)?;
        }
        Ok(changed)
    }

    fn go_parent_directory(&mut self, size: PhysicalSize<u32>) -> Result<bool, String> {
        let pane = self.active_pane();
        let Some(path) = self.parent_directory_path_for_pane(pane) else {
            return Ok(false);
        };
        self.load_path_for_pane(pane, path, size)
    }

    fn go_history_back(&mut self, size: PhysicalSize<u32>) -> Result<bool, String> {
        let pane = self.active_pane();
        let Some(path) = self.pane_history(pane).back.last().cloned() else {
            return Ok(false);
        };
        let current_path = self
            .pane_state(pane)
            .map(|state| state.path.clone())
            .ok_or_else(|| format!("pane {} is not open", pane.as_str()))?;
        {
            let history = self.pane_history_mut(pane);
            history.back.pop();
            history.push_forward(current_path);
        }
        self.load_path_in_pane(pane, path, size, false)
    }

    fn go_history_forward(&mut self, size: PhysicalSize<u32>) -> Result<bool, String> {
        let pane = self.active_pane();
        let Some(path) = self.pane_history(pane).forward.last().cloned() else {
            return Ok(false);
        };
        let current_path = self
            .pane_state(pane)
            .map(|state| state.path.clone())
            .ok_or_else(|| format!("pane {} is not open", pane.as_str()))?;
        {
            let history = self.pane_history_mut(pane);
            history.forward.pop();
            history.push_back(current_path);
        }
        self.load_path_in_pane(pane, path, size, false)
    }

    fn apply_loaded_path_to_pane(
        &mut self,
        pane: ShellPaneId,
        path: PathBuf,
        entries: Vec<Entry>,
        size: PhysicalSize<u32>,
    ) {
        let pane = self.normalized_pane_id(pane);
        let view_mode = self
            .pane_state(pane)
            .map(|state| state.view_mode)
            .unwrap_or(ShellViewMode::Icons);
        let zoom_step = self.pane_zoom_step(pane).unwrap_or(0);
        if let Some(old_path) = self.pane_state(pane).map(|state| state.path.clone()) {
            self.folder_preview_roles
                .borrow_mut()
                .clear_path_prefix(&old_path);
        }
        let filter_pattern = self.filter_pattern_for_pane(pane).to_string();
        self.cancel_metadata_role_work_for_pane(pane);
        self.panes.set(
            pane,
            ShellPaneState::from_entries(
                path,
                view_mode,
                entries,
                self.show_hidden,
                &filter_pattern,
            ),
        );
        if let Some(state) = self.pane_state_mut(pane) {
            state.zoom_step = zoom_step;
        }
        self.invalidate_layout_caches(pane);
        self.visible_slots.clear(pane);
        if let Some(state) = self.pane_state_mut(pane) {
            state.scroll_x = 0.0;
            state.scroll_y = 0.0;
        }
        self.active_pane = pane;
        self.clear_transient_after_pane_content_change(pane, true);
        self.path_changes += 1;
        self.clamp_scroll(size);
    }

    fn clear_transient_after_pane_content_change(&mut self, pane: ShellPaneId, clear_open: bool) {
        if self
            .location_draft
            .as_ref()
            .is_some_and(|draft| draft.pane == pane)
        {
            self.location_draft = None;
        }
        self.rubber_band = None;
        self.scrollbar_drag = None;
        self.last_item_click = None;
        self.context_target = None;
        self.context_menu = None;
        self.drop_menu = None;
        self.properties_overlay = None;
        if clear_open {
            self.create_dialog = None;
            self.rename_dialog = None;
        }
        self.open_with_chooser = None;
        self.trash_conflict_dialog = None;
        self.internal_drag = None;
        self.external_drag = None;
        self.place_press = None;
        self.pending_drop_request = None;
        self.clear_dnd_hover_target();
    }

    fn log_loaded_path_for_pane(
        &self,
        pane: ShellPaneId,
        dir_count: usize,
        preview: &str,
        elapsed: Duration,
    ) {
        let Some(state) = self.pane_state(pane) else {
            return;
        };
        fika_log!(
            "[fika-wgpu] pane={} path={} entries={} dirs={} files={} load={}us changes={}",
            pane.as_str(),
            state.path.display(),
            state.entries.len(),
            dir_count,
            state.entries.len().saturating_sub(dir_count),
            elapsed.as_micros(),
            self.path_changes
        );
        if !preview.is_empty() {
            fika_log!("[fika-wgpu] first-entries={preview}");
        }
    }

    fn log_reloaded_path_for_pane(
        &self,
        pane: ShellPaneId,
        dir_count: usize,
        preview: &str,
        elapsed: Duration,
        selection_changed: bool,
    ) {
        let Some(state) = self.pane_state(pane) else {
            return;
        };
        fika_log!(
            "[fika-wgpu] reload pane={} path={} entries={} dirs={} files={} load={}us reloads={} selected={} selection_changed={}",
            pane.as_str(),
            state.path.display(),
            state.entries.len(),
            dir_count,
            state.entries.len().saturating_sub(dir_count),
            elapsed.as_micros(),
            self.directory_reloads,
            state.selection.len(),
            selection_changed as u8
        );
        if !preview.is_empty() {
            fika_log!("[fika-wgpu] first-entries={preview}");
        }
    }

    fn set_view_mode(&mut self, view_mode: ShellViewMode, size: PhysicalSize<u32>) -> bool {
        let pane_id = self.active_pane();
        let Some(pane) = self.pane_state_mut(pane_id) else {
            return false;
        };
        if pane.view_mode == view_mode {
            return false;
        }
        pane.view_mode = view_mode;
        pane.scroll_x = 0.0;
        pane.scroll_y = 0.0;
        self.visible_slots.clear(pane_id);
        self.folder_preview_roles
            .borrow_mut()
            .clear_request_lifecycle();
        self.rubber_band = None;
        self.scrollbar_drag = None;
        self.view_switches += 1;
        self.clamp_scroll(size);
        fika_log!(
            "[fika-wgpu] view-mode pane={} mode={} switches={} scroll_x={:.1} scroll_y={:.1}",
            pane_id.as_str(),
            view_mode.as_str(),
            self.view_switches,
            self.pane_state(pane_id)
                .map(|pane| pane.scroll_x)
                .unwrap_or(0.0),
            self.pane_state(pane_id)
                .map(|pane| pane.scroll_y)
                .unwrap_or(0.0)
        );
        true
    }

    fn zoom(&mut self, action: ZoomAction, size: PhysicalSize<u32>) -> bool {
        self.zoom_pane(self.active_pane(), action, size)
    }

    fn zoom_pane(
        &mut self,
        pane_id: ShellPaneId,
        action: ZoomAction,
        size: PhysicalSize<u32>,
    ) -> bool {
        let Some(current_step) = self.pane_zoom_step(pane_id) else {
            return false;
        };
        let next_step = match action {
            ZoomAction::In => current_step + 1,
            ZoomAction::Out => current_step - 1,
            ZoomAction::Reset => 0,
        };
        self.set_zoom_step(pane_id, next_step, size, true)
    }

    fn set_zoom_fraction(
        &mut self,
        pane_id: ShellPaneId,
        fraction: f32,
        size: PhysicalSize<u32>,
        clear_scrollbar_drag: bool,
    ) -> bool {
        let span = (DOLPHIN_ZOOM_LEVEL_MAX - DOLPHIN_ZOOM_LEVEL_MIN).max(1) as f32;
        let level = DOLPHIN_ZOOM_LEVEL_MIN + (fraction.clamp(0.0, 1.0) * span).round() as i32;
        self.set_zoom_step(
            pane_id,
            level - DOLPHIN_ZOOM_LEVEL_DEFAULT,
            size,
            clear_scrollbar_drag,
        )
    }

    fn set_zoom_step(
        &mut self,
        pane_id: ShellPaneId,
        next_step: i32,
        size: PhysicalSize<u32>,
        clear_scrollbar_drag: bool,
    ) -> bool {
        let next_step = next_step.clamp(ZOOM_STEP_MIN, ZOOM_STEP_MAX);
        let Some(old_step) = self.pane_zoom_step(pane_id) else {
            return false;
        };
        if next_step == old_step {
            return false;
        }

        if let Some(pane) = self.pane_state_mut(pane_id) {
            pane.zoom_step = next_step;
        }
        self.invalidate_layout_caches_for_pane(pane_id);
        self.folder_preview_roles
            .borrow_mut()
            .clear_request_lifecycle();
        self.rubber_band = None;
        if clear_scrollbar_drag {
            self.scrollbar_drag = None;
        }
        self.zoom_changes += 1;
        let active_pane = self.normalized_pane_id(pane_id);
        if let Some(index) = self
            .pane_selection(active_pane)
            .and_then(ShellSelection::focus_or_first_selected)
        {
            self.ensure_index_visible_in_pane(active_pane, index, size);
        } else {
            self.clamp_scroll(size);
        }
        fika_log!(
            "[fika-wgpu] zoom pane={} step={} percent={} changes={} scroll_x={:.1} scroll_y={:.1}",
            active_pane.as_str(),
            next_step,
            self.zoom_percent_for_pane(active_pane),
            self.zoom_changes,
            self.panes[active_pane].scroll_x,
            self.panes[active_pane].scroll_y
        );
        true
    }

    fn apply_selection_command(&mut self, command: SelectionCommand) -> bool {
        let rubber_band_changed = self.rubber_band.take().is_some();
        let active_pane = self.active_pane();
        let filtered_indexes = self
            .pane_state(active_pane)
            .map(|pane| pane.filtered_indexes.clone())
            .unwrap_or_default();
        let selection_changed = match command {
            SelectionCommand::SelectAll => self
                .pane_selection_mut(active_pane)
                .is_some_and(|selection| selection.select_indexes(&filtered_indexes)),
            SelectionCommand::Clear => self
                .pane_selection_mut(active_pane)
                .is_some_and(ShellSelection::clear),
        };
        if selection_changed {
            self.selection_changes += 1;
        }
        if selection_changed || rubber_band_changed {
            fika_log!(
                "[fika-wgpu] selection command={} selected={} changes={}",
                command.as_str(),
                self.active_selection_len(),
                self.selection_changes
            );
        }
        selection_changed || rubber_band_changed
    }

    fn is_location_editing(&self) -> bool {
        self.location_draft.is_some()
    }

    fn location_draft_pane(&self) -> Option<ShellPaneId> {
        self.location_draft
            .as_ref()
            .map(|draft| self.normalized_pane_id(draft.pane))
    }

    fn location_draft_value(&self) -> Option<&str> {
        self.location_draft
            .as_ref()
            .map(|draft| draft.draft.value.as_str())
    }

    fn location_draft_purpose(&self) -> Option<LocationDraftPurpose> {
        self.location_draft.as_ref().map(|draft| draft.purpose)
    }

    fn location_label_for_pane(&self, pane: ShellPaneId) -> String {
        if let Some(draft) = self
            .location_draft
            .as_ref()
            .filter(|draft| self.normalized_pane_id(draft.pane) == self.normalized_pane_id(pane))
        {
            return draft.draft.value.clone();
        }
        self.pane_state(pane)
            .map(|pane| pane.path.display().to_string())
            .unwrap_or_default()
    }

    fn location_cursor_for_pane(&self, pane: ShellPaneId) -> Option<usize> {
        self.location_draft
            .as_ref()
            .filter(|draft| self.normalized_pane_id(draft.pane) == self.normalized_pane_id(pane))
            .map(|draft| draft.draft.cursor)
    }

    fn location_text_rect_for_path_bar_rect(&self, rect: ViewRect) -> ViewRect {
        let icon_size = self
            .scale_metric(18.0)
            .min((rect.height - self.scale_metric(8.0)).max(1.0));
        let icon_right = rect.x + self.scale_metric(8.0) + icon_size;
        let separator_x = icon_right + self.scale_metric(8.0);
        let text_x = separator_x + self.scale_metric(9.0);
        ViewRect {
            x: text_x,
            y: rect.y + (rect.height - self.text_line_height()) / 2.0,
            width: (rect.right() - text_x - self.scale_metric(8.0)).max(1.0),
            height: self.text_line_height(),
        }
    }

    fn location_cursor_for_screen_point(
        &self,
        pane: ShellPaneId,
        point: ViewPoint,
        size: PhysicalSize<u32>,
    ) -> Option<usize> {
        let rect = self.pane_path_bar_rect(pane, size)?;
        if !rect.contains(point) {
            return None;
        }
        let text_rect = self.location_text_rect_for_path_bar_rect(rect);
        let label = self.location_label_for_pane(pane);
        Some(estimated_text_cursor_for_offset(
            &label,
            point.x - text_rect.x,
            self.scale_metric(TEXT_FONT_SIZE),
        ))
    }

    fn location_bar_active_for_pane(&self, pane: ShellPaneId) -> bool {
        let pane = self.normalized_pane_id(pane);
        self.location_draft_pane() == Some(pane)
            || (self.location_draft.is_none() && self.active_pane() == pane)
    }

    fn resolved_location_draft(&self) -> Option<(ShellPaneId, PathBuf)> {
        let pane = self.location_draft_pane()?;
        let value = self.location_draft_value()?;
        let base = &self.pane_state(pane)?.path;
        resolve_location_input(base, value).map(|path| (pane, path))
    }

    fn close_location_draft(&mut self, size: PhysicalSize<u32>) -> bool {
        if self.location_draft.take().is_none() {
            return false;
        }
        self.location_changes += 1;
        self.rubber_band = None;
        self.clamp_scroll(size);
        fika_log!(
            "[fika-wgpu] location active=0 value=\"\" changes={}",
            self.location_changes
        );
        true
    }

    fn close_location_draft_if_outside(
        &mut self,
        point: ViewPoint,
        size: PhysicalSize<u32>,
    ) -> bool {
        let Some(pane) = self.location_draft_pane() else {
            return false;
        };
        if self
            .pane_path_bar_rect(pane, size)
            .is_some_and(|rect| rect.contains(point))
        {
            return false;
        }
        self.close_location_draft(size)
    }

    fn activate_path_bar_at_screen_point(
        &mut self,
        point: ViewPoint,
        size: PhysicalSize<u32>,
    ) -> bool {
        let Some(pane) = self.path_bar_pane_at_screen_point(point, size) else {
            return false;
        };
        let pane = self.normalized_pane_id(pane);
        let old_pane = self.active_pane();
        let old_draft = self.location_draft.clone();
        let old_filter_active = self.filter_active;
        self.active_pane = self.normalized_pane_id(pane);
        if self.location_draft_pane() != Some(pane) {
            let Some(path) = self.pane_state(pane).map(|pane| pane.path.clone()) else {
                return old_pane != self.active_pane();
            };
            self.location_draft = Some(ShellLocationDraft::new(pane, path.display().to_string()));
            self.filter_active = false;
        }
        if let Some(cursor) = self.location_cursor_for_screen_point(pane, point, size)
            && let Some(draft) = self.location_draft.as_mut()
        {
            draft.draft.set_cursor(cursor);
        }

        let location_changed =
            old_draft != self.location_draft || old_filter_active != self.filter_active;
        if location_changed {
            self.reset_text_caret_blink();
            self.location_changes += 1;
            self.rubber_band = None;
            self.clamp_scroll(size);
            fika_log!(
                "[fika-wgpu] location active={} value={:?} changes={}",
                self.location_draft.is_some() as u8,
                self.location_draft_value().unwrap_or(""),
                self.location_changes
            );
        }
        location_changed || old_pane != self.active_pane()
    }

    fn open_add_network_folder_location_draft(&mut self, size: PhysicalSize<u32>) -> bool {
        let old_draft = self.location_draft.clone();
        let pane = self.active_pane();
        self.location_draft = Some(ShellLocationDraft::add_network_folder(pane));
        self.filter_active = false;
        self.context_target = None;
        self.context_menu = None;
        self.drop_menu = None;
        self.properties_overlay = None;
        self.create_dialog = None;
        self.rename_dialog = None;
        self.open_with_chooser = None;
        self.rubber_band = None;
        let changed = old_draft != self.location_draft;
        if changed {
            self.reset_text_caret_blink();
            self.location_changes += 1;
            self.clamp_scroll(size);
            fika_log!(
                "[fika-wgpu] add-network-folder input=1 value={:?} changes={}",
                self.location_draft_value().unwrap_or(""),
                self.location_changes
            );
        }
        changed
    }

    fn add_network_folder_request_from_draft(&self) -> Result<AddNetworkFolderRequest, String> {
        let Some(draft) = self.location_draft.as_ref() else {
            return Err("network folder input is not open".to_string());
        };
        if draft.purpose != LocationDraftPurpose::AddNetworkFolder {
            return Err("location input is not adding a network folder".to_string());
        }
        let pane = self.normalized_pane_id(draft.pane);
        let input = draft.draft.value.trim();
        let path = network_path_from_uri(input).map_err(|error| error.to_string())?;
        if path == network_root_path() {
            return Err("enter a network server or share URL".to_string());
        }
        let label = network_path_display_name(&path)
            .filter(|label| !label.trim().is_empty())
            .unwrap_or_else(|| path.display().to_string());
        Ok(AddNetworkFolderRequest { pane, path, label })
    }

    fn apply_location_command(
        &mut self,
        command: LocationCommand,
        size: PhysicalSize<u32>,
    ) -> bool {
        let old_draft = self.location_draft.clone();
        let old_filter_active = self.filter_active;
        let reset_caret_on_noop = matches!(
            &command,
            LocationCommand::Activate
                | LocationCommand::Insert(_)
                | LocationCommand::Backspace
                | LocationCommand::Delete
                | LocationCommand::MoveLeft
                | LocationCommand::MoveRight
                | LocationCommand::MoveHome
                | LocationCommand::MoveEnd
                | LocationCommand::Complete
        );

        match command {
            LocationCommand::Activate => {
                let pane = self.active_pane();
                let Some(path) = self.pane_state(pane).map(|pane| pane.path.clone()) else {
                    return false;
                };
                self.location_draft =
                    Some(ShellLocationDraft::new(pane, path.display().to_string()));
                self.filter_active = false;
            }
            LocationCommand::Insert(value) => {
                let Some(draft) = self.location_draft.as_mut() else {
                    return false;
                };
                draft.draft.insert(&value);
            }
            LocationCommand::Backspace => {
                let Some(draft) = self.location_draft.as_mut() else {
                    return false;
                };
                draft.draft.backspace();
            }
            LocationCommand::Delete => {
                let Some(draft) = self.location_draft.as_mut() else {
                    return false;
                };
                draft.draft.delete();
            }
            LocationCommand::MoveLeft => {
                let Some(draft) = self.location_draft.as_mut() else {
                    return false;
                };
                draft.draft.move_left();
            }
            LocationCommand::MoveRight => {
                let Some(draft) = self.location_draft.as_mut() else {
                    return false;
                };
                draft.draft.move_right();
            }
            LocationCommand::MoveHome => {
                let Some(draft) = self.location_draft.as_mut() else {
                    return false;
                };
                draft.draft.move_home();
            }
            LocationCommand::MoveEnd => {
                let Some(draft) = self.location_draft.as_mut() else {
                    return false;
                };
                draft.draft.move_end();
            }
            LocationCommand::Cancel => {
                self.location_draft = None;
            }
            LocationCommand::Complete => {
                let Some(location) = self.location_draft.as_ref() else {
                    return false;
                };
                let pane = self.normalized_pane_id(location.pane);
                let Some(base) = self.pane_state(pane).map(|pane| pane.path.clone()) else {
                    return false;
                };
                let Some(completed) = complete_location_input(&base, &location.draft.value) else {
                    return false;
                };
                if let Some(draft) = self.location_draft.as_mut() {
                    draft.draft.set_completed(completed);
                }
            }
            LocationCommand::Commit | LocationCommand::Ignore => return false,
        }

        let changed = old_draft != self.location_draft || old_filter_active != self.filter_active;
        if !changed {
            if reset_caret_on_noop && self.location_text_caret_active() {
                self.reset_text_caret_blink();
                return true;
            }
            return false;
        }

        self.reset_text_caret_blink();
        self.location_changes += 1;
        self.rubber_band = None;
        self.clamp_scroll(size);
        fika_log!(
            "[fika-wgpu] location active={} value={:?} changes={}",
            self.location_draft.is_some() as u8,
            self.location_draft_value().unwrap_or(""),
            self.location_changes
        );
        true
    }

    fn apply_filter_command(&mut self, command: FilterCommand, size: PhysicalSize<u32>) -> bool {
        let old_active = self.filter_active;
        let old_pattern = self.filter_pattern.clone();

        match command {
            FilterCommand::Activate => {
                self.filter_active = true;
            }
            FilterCommand::Insert(value) => {
                self.filter_active = true;
                self.filter_pattern.push_str(&value);
            }
            FilterCommand::Backspace => {
                self.filter_active = true;
                self.filter_pattern.pop();
            }
            FilterCommand::ClearAndDeactivate => {
                self.filter_active = false;
                self.filter_pattern.clear();
            }
            FilterCommand::Deactivate => {
                self.filter_active = false;
            }
        }

        let filter_changed = old_active != self.filter_active || old_pattern != self.filter_pattern;
        if !filter_changed {
            return false;
        }

        self.filter_changes += 1;
        self.rubber_band = None;
        let selection_changed = self.rebuild_filtered_indexes();
        if selection_changed {
            self.selection_changes += 1;
        }
        self.clamp_scroll(size);
        fika_log!(
            "[fika-wgpu] filter active={} pattern={:?} matches={} changes={} selection_changed={}",
            self.filter_active as u8,
            self.filter_pattern,
            self.panes[ShellPaneId::SLOT_0].filtered_indexes.len(),
            self.filter_changes,
            selection_changed as u8
        );
        true
    }

    fn toggle_hidden_visibility(&mut self, size: PhysicalSize<u32>) -> bool {
        self.show_hidden = !self.show_hidden;
        self.hidden_changes += 1;
        self.rubber_band = None;
        let selection_changed = self.rebuild_filtered_indexes();
        if selection_changed {
            self.selection_changes += 1;
        }
        self.clamp_scroll(size);
        fika_log!(
            "[fika-wgpu] hidden show={} visible={} changes={} selection_changed={}",
            self.show_hidden as u8,
            self.filtered_entry_count(),
            self.hidden_changes,
            selection_changed as u8
        );
        true
    }

    fn theme(&self) -> ShellTheme {
        ShellTheme::for_dark_mode(self.dark_mode)
    }

    fn toggle_dark_mode(&mut self) {
        self.dark_mode = !self.dark_mode;
        self.view_switches += 1;
        self.rubber_band = None;
        self.animations.clear();
        fika_log!(
            "[fika-wgpu] dark-mode enabled={} view_switches={}",
            self.dark_mode as u8,
            self.view_switches
        );
    }

    fn open_split_pane_from_context(&mut self, size: PhysicalSize<u32>) -> Result<bool, String> {
        let (path, source_pane) = self.context_target_split_pane_request().unwrap_or_else(|| {
            let pane = self.active_pane();
            let path = self
                .pane_state(pane)
                .map(|pane| pane.path.clone())
                .unwrap_or_else(|| self.panes[ShellPaneId::SLOT_0].path.clone());
            (path, pane)
        });
        let view_mode = self
            .pane_state(source_pane)
            .map(|pane| pane.view_mode)
            .unwrap_or_else(|| self.active_view_mode());
        let zoom_step = self.pane_zoom_step(source_pane).unwrap_or(0);
        self.open_split_pane_with_view_mode(path, view_mode, zoom_step, size)
    }

    #[cfg(test)]
    fn open_split_pane(&mut self, path: PathBuf, size: PhysicalSize<u32>) -> Result<bool, String> {
        let view_mode = self.active_view_mode();
        let zoom_step = self.active_zoom_step();
        self.open_split_pane_with_view_mode(path, view_mode, zoom_step, size)
    }

    fn open_split_pane_with_view_mode(
        &mut self,
        path: PathBuf,
        view_mode: ShellViewMode,
        zoom_step: i32,
        size: PhysicalSize<u32>,
    ) -> Result<bool, String> {
        let mut split_pane = ShellPaneState::load(path, view_mode, self.show_hidden)?;
        split_pane.zoom_step = zoom_step.clamp(ZOOM_STEP_MIN, ZOOM_STEP_MAX);
        split_pane.scroll_x = 0.0;
        split_pane.scroll_y = 0.0;
        self.panes.set(ShellPaneId::SLOT_1, split_pane);
        self.invalidate_layout_caches(ShellPaneId::SLOT_1);
        self.visible_slots.clear(ShellPaneId::SLOT_1);
        self.active_pane = ShellPaneId::SLOT_1;
        self.split_pane_left_fraction = 0.5;
        self.split_pane_changes += 1;
        self.context_target = None;
        self.context_menu = None;
        self.drop_menu = None;
        self.properties_overlay = None;
        self.create_dialog = None;
        self.rename_dialog = None;
        self.open_with_chooser = None;
        self.trash_conflict_dialog = None;
        self.internal_drag = None;
        self.external_drag = None;
        self.place_press = None;
        self.pending_drop_request = None;
        self.clear_dnd_hover_target();
        self.rubber_band = None;
        self.scrollbar_drag = None;
        self.clamp_scroll(size);
        fika_log!(
            "[fika-wgpu] split-pane open=1 changes={} left={} right={}",
            self.split_pane_changes,
            self.panes[ShellPaneId::SLOT_0].path.display(),
            self.panes
                .get(ShellPaneId::SLOT_1)
                .map(|pane| pane.path.display().to_string())
                .unwrap_or_default()
        );
        Ok(true)
    }

    fn open_split_pane_from_active(&mut self, size: PhysicalSize<u32>) -> Result<bool, String> {
        let pane = self.active_pane();
        let Some(state) = self.pane_state(pane) else {
            return Err(format!("pane {} is not open", pane.as_str()));
        };
        let current_path = state.path.clone();
        let view_mode = state.view_mode;
        let zoom_step = state.zoom_step;
        let path = self
            .single_selected_directory_path_for_pane(pane)
            .unwrap_or(current_path);
        self.open_split_pane_with_view_mode(path, view_mode, zoom_step, size)
    }

    fn toggle_split_view_from_toolbar(&mut self, size: PhysicalSize<u32>) -> Result<bool, String> {
        if self.panes.is_open(ShellPaneId::SLOT_1) {
            Ok(self.close_active_split_pane(size))
        } else {
            self.open_split_pane_from_active(size)
        }
    }

    fn close_active_split_pane(&mut self, size: PhysicalSize<u32>) -> bool {
        if !self.panes.is_open(ShellPaneId::SLOT_1) {
            return false;
        }
        let active = self.active_pane();
        match active {
            ShellPaneId::SLOT_0 => {
                let Some(remaining) = self.panes.take(ShellPaneId::SLOT_1) else {
                    return false;
                };
                self.panes.set(ShellPaneId::SLOT_0, remaining);
                let remaining_history = self.histories.take(ShellPaneId::SLOT_1);
                self.histories.set(ShellPaneId::SLOT_0, remaining_history);
                self.histories.clear(ShellPaneId::SLOT_1);
            }
            ShellPaneId::SLOT_1 => {
                if self.panes.take(ShellPaneId::SLOT_1).is_none() {
                    return false;
                }
                self.histories.clear(ShellPaneId::SLOT_1);
            }
        }
        self.active_pane = ShellPaneId::SLOT_0;
        self.visible_slots.clear(ShellPaneId::SLOT_0);
        self.visible_slots.clear(ShellPaneId::SLOT_1);
        self.invalidate_all_layout_caches();
        self.split_pane_left_fraction = 0.5;
        self.split_pane_changes += 1;
        self.context_target = None;
        self.context_menu = None;
        self.drop_menu = None;
        self.properties_overlay = None;
        self.create_dialog = None;
        self.rename_dialog = None;
        self.open_with_chooser = None;
        self.trash_conflict_dialog = None;
        self.internal_drag = None;
        self.external_drag = None;
        self.place_press = None;
        self.pending_drop_request = None;
        self.clear_dnd_hover_target();
        self.rubber_band = None;
        self.scrollbar_drag = None;
        self.clamp_scroll(size);
        fika_log!(
            "[fika-wgpu] split-pane open=0 closed={} changes={} remaining={}",
            active.as_str(),
            self.split_pane_changes,
            self.panes[ShellPaneId::SLOT_0].path.display()
        );
        true
    }

    #[cfg(test)]
    fn context_target_split_pane_path(&self) -> Option<PathBuf> {
        self.context_target_split_pane_request()
            .map(|(path, _pane)| path)
    }

    fn context_target_split_pane_request(&self) -> Option<(PathBuf, ShellPaneId)> {
        match self.context_target.as_ref()? {
            ShellContextTarget::Item {
                pane, path, is_dir, ..
            } if *is_dir => Some((path.clone(), self.normalized_pane_id(*pane))),
            ShellContextTarget::Item { pane, path, .. } => path
                .parent()
                .filter(|parent| !parent.as_os_str().is_empty())
                .map(Path::to_path_buf)
                .or_else(|| self.pane_state(*pane).map(|state| state.path.clone()))
                .map(|path| (path, self.normalized_pane_id(*pane))),
            ShellContextTarget::Blank { pane, path, .. } => {
                Some((path.clone(), self.normalized_pane_id(*pane)))
            }
            ShellContextTarget::Place { path, .. } => Some((path.clone(), self.active_pane())),
        }
    }

    fn single_selected_directory_path_for_pane(&self, pane: ShellPaneId) -> Option<PathBuf> {
        let selection = self.pane_selection(pane)?;
        if selection.len() != 1 {
            return None;
        }
        selection
            .focus_or_first_selected()
            .and_then(|index| self.directory_path_for_pane_index(pane, index))
    }

    fn rebuild_filtered_indexes(&mut self) -> bool {
        let mut selection_changed = false;
        let show_hidden = self.show_hidden;
        for pane in ShellPaneId::ALL {
            let filter_pattern = self.filter_pattern_for_pane(pane).to_string();
            if let Some(state) = self.pane_state_mut(pane) {
                selection_changed |=
                    state.rebuild_filtered_indexes_with_pattern(show_hidden, &filter_pattern);
                self.invalidate_layout_caches(pane);
            }
        }
        selection_changed
    }

    fn filtered_entry_count(&self) -> usize {
        self.panes[ShellPaneId::SLOT_0].filtered_indexes.len()
    }

    fn set_scale_factor(&mut self, scale_factor: f32, size: PhysicalSize<u32>) -> bool {
        let next = normalized_scale_factor(scale_factor);
        if (self.scale_factor - next).abs() <= 0.01 {
            self.scale_factor = next;
            self.clamp_scroll(size);
            return false;
        }

        let old_ui_scale = self.ui_scale();
        self.scale_factor = next;
        self.invalidate_all_layout_caches();
        self.folder_preview_roles
            .borrow_mut()
            .clear_request_lifecycle();
        let next_ui_scale = self.ui_scale();
        if old_ui_scale > f32::EPSILON {
            let ratio = next_ui_scale / old_ui_scale;
            for pane in ShellPaneId::ALL {
                if let Some(state) = self.pane_state_mut(pane) {
                    state.scroll_x *= ratio;
                    state.scroll_y *= ratio;
                }
            }
            self.places_scroll_y *= ratio;
        }
        self.clamp_scroll(size);
        fika_log!(
            "[fika-wgpu] scale-factor={:.2} ui_scale={:.2} scroll_x={:.1} scroll_y={:.1}",
            self.scale_factor,
            self.ui_scale(),
            self.panes[ShellPaneId::SLOT_0].scroll_x,
            self.panes[ShellPaneId::SLOT_0].scroll_y
        );
        true
    }

    fn ui_scale(&self) -> f32 {
        normalized_scale_factor(self.scale_factor).max(1.0)
    }

    fn scale_metric(&self, value: f32) -> f32 {
        (value * self.ui_scale()).round().max(1.0)
    }

    fn pane_zoom_step(&self, pane: ShellPaneId) -> Option<i32> {
        self.pane_state(self.normalized_pane_id(pane))
            .map(|pane| pane.zoom_step)
    }

    #[cfg(test)]
    fn active_zoom_step(&self) -> i32 {
        self.pane_zoom_step(self.active_pane()).unwrap_or(0)
    }

    fn dolphin_zoom_level_for_step(&self, zoom_step: i32) -> i32 {
        (zoom_step + DOLPHIN_ZOOM_LEVEL_DEFAULT)
            .clamp(DOLPHIN_ZOOM_LEVEL_MIN, DOLPHIN_ZOOM_LEVEL_MAX)
    }

    fn dolphin_zoom_icon_size_for_step(&self, zoom_step: i32) -> f32 {
        dolphin_icon_size_for_zoom_level(self.dolphin_zoom_level_for_step(zoom_step))
    }

    fn zoom_icon_factor_for_step(&self, zoom_step: i32) -> f32 {
        self.dolphin_zoom_icon_size_for_step(zoom_step)
            / dolphin_icon_size_for_zoom_level(DOLPHIN_ZOOM_LEVEL_DEFAULT)
    }

    fn zoom_icon_metric_for_step(&self, zoom_step: i32, value: f32, min: f32, max: f32) -> f32 {
        let scale = self.ui_scale();
        (value * self.zoom_icon_factor_for_step(zoom_step) * scale)
            .round()
            .clamp(min * scale, max * scale)
    }

    fn icons_text_width_factor_for_step(&self, zoom_step: i32) -> f32 {
        let default = (DOLPHIN_ZOOM_LEVEL_DEFAULT as f32 / 13.0).exp();
        (self.dolphin_zoom_level_for_step(zoom_step) as f32 / 13.0).exp() / default
    }

    fn text_line_height(&self) -> f32 {
        self.scale_metric(TEXT_LINE_HEIGHT)
    }

    fn small_text_line_height(&self) -> f32 {
        self.scale_metric(14.0)
    }

    fn app_toolbar_height(&self) -> f32 {
        self.scale_metric(APP_TOOLBAR_HEIGHT)
    }

    fn app_toolbar_y(&self) -> f32 {
        0.0
    }

    fn pane_margin(&self) -> f32 {
        self.scale_metric(PANE_MARGIN)
    }

    fn pane_top_y(&self) -> f32 {
        self.app_toolbar_height() + self.pane_margin()
    }

    fn top_bar_height(&self) -> f32 {
        self.scale_metric(TOP_BAR_HEIGHT)
    }

    fn status_bar_height(&self) -> f32 {
        self.scale_metric(STATUS_BAR_HEIGHT)
    }

    fn details_header_height(&self) -> f32 {
        self.scale_metric(DETAILS_HEADER_HEIGHT)
    }

    fn details_name_width(&self) -> f32 {
        self.scale_metric(DETAILS_NAME_WIDTH)
    }

    fn details_size_width(&self) -> f32 {
        self.scale_metric(DETAILS_SIZE_WIDTH)
    }

    fn details_modified_width(&self) -> f32 {
        self.scale_metric(DETAILS_MODIFIED_WIDTH)
    }

    fn selection_for_reloaded_pane_entries(
        &self,
        pane_id: ShellPaneId,
        entries: &[Entry],
    ) -> ShellSelection {
        let Some(pane) = self.pane_state(pane_id) else {
            return ShellSelection::default();
        };
        if pane.selection.selected.is_empty() {
            return ShellSelection::default();
        }

        let selected_names = pane
            .selection
            .selected
            .iter()
            .filter_map(|index| pane.entries.get(*index))
            .map(|entry| entry.name.to_string())
            .collect::<BTreeSet<_>>();
        let anchor_name = pane
            .selection
            .anchor
            .and_then(|index| pane.entries.get(index))
            .map(|entry| entry.name.to_string());
        let focus_name = pane
            .selection
            .focus
            .and_then(|index| pane.entries.get(index))
            .map(|entry| entry.name.to_string());

        let selected = entries
            .iter()
            .enumerate()
            .filter_map(|(index, entry)| {
                selected_names
                    .contains(entry.name.as_ref())
                    .then_some(index)
            })
            .collect::<BTreeSet<_>>();
        if selected.is_empty() {
            return ShellSelection::default();
        }

        let anchor = anchor_name
            .and_then(|name| entry_index_by_name(entries, &name))
            .filter(|index| selected.contains(index))
            .or_else(|| selected.iter().next().copied());
        let focus = focus_name
            .and_then(|name| entry_index_by_name(entries, &name))
            .filter(|index| selected.contains(index))
            .or_else(|| selected.iter().next_back().copied());

        ShellSelection {
            selected,
            anchor,
            focus,
        }
    }

    fn view_mode_at_screen_point(
        &self,
        point: ViewPoint,
        size: PhysicalSize<u32>,
    ) -> Option<ShellViewMode> {
        self.toolbar_view_mode_segment_at_screen_point(point, size)
            .map(|segment| segment.mode)
    }

    fn pane_path_bar_rect(&self, kind: ShellPaneId, size: PhysicalSize<u32>) -> Option<ViewRect> {
        let pane = self.pane_state(kind)?;
        let geometry = self.pane_geometry(kind, size)?;
        let margin = self.scale_metric(8.0);
        let path_x = geometry.pane.x + margin;
        let available_width = (geometry.pane.right() - path_x - margin).max(0.0);
        let rect = ViewRect {
            x: path_x,
            y: geometry.pane.y + self.scale_metric(4.0),
            width: available_width,
            height: self.scale_metric(28.0),
        };
        let _ = pane;
        (rect.width > self.scale_metric(24.0)).then_some(rect)
    }

    #[cfg(test)]
    fn path_bar_rect(&self, size: PhysicalSize<u32>) -> Option<ViewRect> {
        self.pane_path_bar_rect(ShellPaneId::SLOT_0, size)
    }

    fn path_bar_contains_screen_point(&self, point: ViewPoint, size: PhysicalSize<u32>) -> bool {
        self.path_bar_pane_at_screen_point(point, size).is_some()
    }

    fn path_bar_pane_at_screen_point(
        &self,
        point: ViewPoint,
        size: PhysicalSize<u32>,
    ) -> Option<ShellPaneId> {
        ShellPaneId::ALL.into_iter().find(|kind| {
            self.pane_path_bar_rect(*kind, size)
                .is_some_and(|rect| rect.contains(point))
        })
    }

    fn path_navigation_action_at_screen_point(
        &self,
        point: ViewPoint,
        _size: PhysicalSize<u32>,
    ) -> Option<PathNavigationAction> {
        let _ = point;
        None
    }

    fn app_toolbar_rect(&self, size: PhysicalSize<u32>) -> ViewRect {
        ViewRect {
            x: 0.0,
            y: self.app_toolbar_y(),
            width: size.width.max(1) as f32,
            height: self.app_toolbar_height(),
        }
    }

    fn app_toolbar_layout(&self, size: PhysicalSize<u32>) -> ShellToolbarLayout {
        let toolbar = self.app_toolbar_rect(size);
        let margin = self.scale_metric(8.0);
        let button_size = self
            .scale_metric(28.0)
            .min((toolbar.height - margin).max(1.0));
        let places_toggle = ViewRect {
            x: margin,
            y: toolbar.y + margin,
            width: button_size,
            height: button_size,
        };
        let split_view = ViewRect {
            x: (toolbar.right() - margin - button_size).max(toolbar.x),
            y: toolbar.y + margin,
            width: button_size,
            height: button_size,
        };
        let view_mode = self.toolbar_view_mode_control(toolbar, places_toggle, split_view);
        ShellToolbarLayout {
            toolbar,
            places_toggle,
            split_view,
            view_mode,
        }
    }

    fn toolbar_view_mode_control(
        &self,
        toolbar: ViewRect,
        places_toggle: ViewRect,
        split_view: ViewRect,
    ) -> Option<ShellToolbarViewModeControl> {
        let width = self.scale_metric(96.0);
        let gap_to_split = self.scale_metric(10.0);
        if split_view.x - gap_to_split - width <= places_toggle.right() + self.scale_metric(16.0) {
            return None;
        }
        let outer = ViewRect {
            x: split_view.x - gap_to_split - width,
            y: toolbar.y + self.scale_metric(7.0),
            width,
            height: (toolbar.height - self.scale_metric(14.0)).max(1.0),
        };
        let inner = inset_rect(outer, self.scale_metric(2.0)).unwrap_or(outer);
        let gap = self.scale_metric(2.0).min((inner.width / 8.0).max(0.0));
        let segment_width = ((inner.width - gap * 2.0) / 3.0).max(1.0);
        let modes = [
            ShellViewMode::Icons,
            ShellViewMode::Compact,
            ShellViewMode::Details,
        ];
        let segments = modes.map(|mode| {
            let index = match mode {
                ShellViewMode::Icons => 0,
                ShellViewMode::Compact => 1,
                ShellViewMode::Details => 2,
            } as f32;
            ShellToolbarViewModeSegment {
                mode,
                rect: ViewRect {
                    x: inner.x + index * (segment_width + gap),
                    y: inner.y,
                    width: segment_width,
                    height: inner.height,
                },
            }
        });
        Some(ShellToolbarViewModeControl { outer, segments })
    }

    fn places_toggle_rect(&self, size: PhysicalSize<u32>) -> ViewRect {
        self.app_toolbar_layout(size).places_toggle
    }

    fn split_view_button_rect(&self, size: PhysicalSize<u32>) -> ViewRect {
        self.app_toolbar_layout(size).split_view
    }

    fn toolbar_view_mode_badge_rect(&self, size: PhysicalSize<u32>) -> Option<ViewRect> {
        self.app_toolbar_layout(size)
            .view_mode
            .map(|control| control.outer)
    }

    fn toolbar_view_mode_segment_at_screen_point(
        &self,
        point: ViewPoint,
        size: PhysicalSize<u32>,
    ) -> Option<ShellToolbarViewModeSegment> {
        self.app_toolbar_layout(size)
            .view_mode?
            .segments
            .into_iter()
            .find(|segment| segment.rect.contains(point))
    }

    fn split_view_button_at_screen_point(&self, point: ViewPoint, size: PhysicalSize<u32>) -> bool {
        self.split_view_button_rect(size).contains(point)
    }

    fn places_toggle_contains_screen_point(
        &self,
        point: ViewPoint,
        size: PhysicalSize<u32>,
    ) -> bool {
        self.places_toggle_rect(size).contains(point)
    }

    fn toggle_places_at_screen_point(
        &mut self,
        point: ViewPoint,
        size: PhysicalSize<u32>,
    ) -> Option<bool> {
        self.places_toggle_rect(size)
            .contains(point)
            .then(|| self.toggle_places_visibility(size))
    }

    fn toggle_places_visibility(&mut self, size: PhysicalSize<u32>) -> bool {
        self.places_visible = !self.places_visible;
        self.places_changes += 1;
        self.scrollbar_drag = None;
        self.rubber_band = None;
        self.hovered_place = None;
        self.last_item_click = None;
        self.clamp_scroll(size);
        fika_log!(
            "[fika-wgpu] places visible={} width={:.1} changes={}",
            self.places_visible as u8,
            self.places_sidebar_width(size),
            self.places_changes
        );
        true
    }

    fn places_resize_handle_rect(&self, size: PhysicalSize<u32>) -> Option<ViewRect> {
        if !self.places_visible {
            return None;
        }
        let sidebar = self.places_sidebar_rect(size);
        if sidebar.width <= 0.0 || sidebar.height <= 0.0 {
            return None;
        }
        let handle_width = self
            .scale_metric(PLACES_RESIZE_HANDLE_WIDTH)
            .max(self.scale_metric(PLACES_SIDEBAR_SPLITTER_WIDTH));
        let splitter_cover = self.scale_metric(PLACES_SIDEBAR_SPLITTER_WIDTH + 2.0);
        Some(ViewRect {
            x: (sidebar.right() - handle_width).max(sidebar.x),
            y: sidebar.y,
            width: (handle_width + splitter_cover).min(sidebar.width + splitter_cover),
            height: sidebar.height,
        })
    }

    fn split_pane_resize_handle_rect(&self, size: PhysicalSize<u32>) -> Option<ViewRect> {
        let divider = self.split_pane_metrics(size)?.divider;
        let handle_width = self
            .scale_metric(SPLIT_PANE_RESIZE_HANDLE_WIDTH)
            .max(divider.width);
        Some(ViewRect {
            x: divider.x + (divider.width - handle_width) / 2.0,
            y: divider.y,
            width: handle_width,
            height: divider.height,
        })
    }

    fn cursor_icon(&self, size: PhysicalSize<u32>) -> CursorIcon {
        if self.scrollbar_drag.is_some_and(|drag| {
            matches!(
                drag.target,
                ScrollbarDragTarget::PlacesResize | ScrollbarDragTarget::SplitPaneResize
            )
        }) {
            return CursorIcon::ColResize;
        }
        if self
            .scrollbar_drag
            .is_some_and(|drag| matches!(drag.target, ScrollbarDragTarget::StatusZoom { .. }))
        {
            return CursorIcon::Pointer;
        }
        if self.scrollbar_drag.is_some() {
            return CursorIcon::Default;
        }
        let Some(point) = self.pointer else {
            return CursorIcon::Default;
        };
        if self
            .places_scrollbar_rects(size)
            .is_some_and(|(track, _)| track.contains(point))
        {
            return CursorIcon::Default;
        }
        if self
            .places_task_area_rect(size)
            .is_some_and(|rect| rect.contains(point))
        {
            return CursorIcon::Pointer;
        }
        if self.places_toggle_contains_screen_point(point, size)
            || self.split_view_button_at_screen_point(point, size)
            || self.status_zoom_contains_screen_point(point, size)
            || self
                .toolbar_view_mode_badge_rect(size)
                .is_some_and(|rect| rect.contains(point))
        {
            return CursorIcon::Pointer;
        }
        if self
            .places_resize_handle_rect(size)
            .is_some_and(|rect| rect.contains(point))
            || self
                .split_pane_resize_handle_rect(size)
                .is_some_and(|rect| rect.contains(point))
        {
            CursorIcon::ColResize
        } else if self.path_bar_contains_screen_point(point, size) {
            CursorIcon::Text
        } else {
            CursorIcon::Default
        }
    }

    fn open_with_chooser_cursor_icon(&self, size: PhysicalSize<u32>) -> CursorIcon {
        let Some(point) = self.pointer else {
            return CursorIcon::Default;
        };
        let Some(chooser) = self.open_with_chooser.as_ref() else {
            return CursorIcon::Default;
        };
        match open_with_chooser_pointer_role_at_point(chooser, point, size, self.ui_scale()) {
            OpenWithChooserPointerRole::Text => CursorIcon::Text,
            OpenWithChooserPointerRole::Action => CursorIcon::Pointer,
            OpenWithChooserPointerRole::Default => CursorIcon::Default,
        }
    }

    #[cfg_attr(not(test), allow(dead_code))]
    fn place_activation_for_press(
        &mut self,
        point: ViewPoint,
        size: PhysicalSize<u32>,
    ) -> Option<ShellPlaceActivation> {
        let index = self.place_index_at_screen_point(point, size)?;
        self.activate_place_index(index, point)
    }

    fn activate_place_index(
        &mut self,
        index: usize,
        point: ViewPoint,
    ) -> Option<ShellPlaceActivation> {
        let target_pane = self.active_pane();
        self.pointer = Some(point);
        let hover_changed = self.set_hovered_place(Some(index));
        let item_hover_changed = self.set_hovered_item(None);
        self.rubber_band = None;
        self.internal_drag = None;
        self.external_drag = None;
        self.place_press = None;
        self.last_item_click = None;
        self.context_target = None;
        self.context_menu = None;
        self.drop_menu = None;
        let place = self.places.get(index)?;
        if place.device.as_ref().is_some_and(|device| !device.mounted) {
            let device = place.device.as_ref()?;
            self.places_changes += 1;
            fika_log!(
                "[fika-wgpu] place-mount index={} label={:?} target_pane={} path={} changes={}",
                index,
                place.label,
                target_pane.as_str(),
                place.path.display(),
                self.places_changes
            );
            return Some(ShellPlaceActivation::DeviceAction(DeviceActionRequest {
                id: device.id.clone(),
                label: place.label.clone(),
                action: ShellContextMenuAction::MountDevice,
                operation: DevicePlaceOperation::Mount,
                pane: target_pane,
                path: place.path.clone(),
            }));
        }
        self.places_changes += 1;
        fika_log!(
            "[fika-wgpu] place-open index={} label={:?} target_pane={} path={} hover_changed={} item_hover_changed={} changes={}",
            index,
            place.label,
            target_pane.as_str(),
            place.path.display(),
            hover_changed as u8,
            item_hover_changed as u8,
            self.places_changes
        );
        Some(ShellPlaceActivation::Open {
            pane: target_pane,
            path: place.path.clone(),
        })
    }

    fn begin_place_pointer(&mut self, point: ViewPoint, size: PhysicalSize<u32>) -> Option<bool> {
        let index = self.place_index_at_screen_point(point, size)?;
        self.pointer = Some(point);
        let hover_changed = self.set_hovered_place(Some(index));
        let item_hover_changed = self.set_hovered_item(None);
        self.rubber_band = None;
        self.external_drag = None;
        self.last_item_click = None;
        self.context_target = None;
        self.context_menu = None;
        self.drop_menu = None;
        let drag_started = if self.place_participates_in_dnd(index) {
            self.place_press = None;
            self.begin_internal_drag_for_place(index, point)
        } else {
            self.place_press = Some(ShellPlacePress { index, point });
            self.internal_drag = None;
            false
        };
        Some(hover_changed || item_hover_changed || drag_started)
    }

    fn place_pointer_target_at_screen_point(
        &self,
        point: ViewPoint,
        size: PhysicalSize<u32>,
    ) -> bool {
        self.place_index_at_screen_point(point, size).is_some()
    }

    fn place_pointer_active(&self) -> bool {
        self.place_press.is_some()
            || self
                .internal_drag
                .as_ref()
                .and_then(ShellInternalDrag::source_place_index)
                .is_some()
    }

    #[cfg_attr(not(test), allow(dead_code))]
    fn active_place_drag_source_index(&self) -> Option<usize> {
        self.internal_drag
            .as_ref()
            .filter(|drag| drag.active)
            .and_then(ShellInternalDrag::source_place_index)
    }

    fn end_place_pointer(
        &mut self,
        point: ViewPoint,
        size: PhysicalSize<u32>,
    ) -> (bool, Option<ShellPlaceActivation>) {
        self.pointer = Some(point);
        if let Some(source_index) = self
            .internal_drag
            .as_ref()
            .and_then(ShellInternalDrag::source_place_index)
        {
            let was_active = self.internal_drag.as_ref().is_some_and(|drag| drag.active);
            self.place_press = None;
            let drop_changed = self.finish_internal_drag(point, size);
            let hover_changed = self.refresh_hover(size);
            let activation = if !was_active
                && self.place_index_at_screen_point(point, size) == Some(source_index)
            {
                self.activate_place_index(source_index, point)
            } else {
                None
            };
            return (
                was_active || drop_changed || hover_changed || activation.is_some(),
                activation,
            );
        }

        let press = self.place_press.take();
        let Some(source_index) = press.as_ref().map(|press| press.index) else {
            return (self.refresh_hover(size), None);
        };
        let _ = self.clear_dnd_hover_target();
        let within_click_distance = press
            .as_ref()
            .is_none_or(|press| point_distance(press.point, point) < RUBBER_BAND_START_THRESHOLD);
        let activation = if within_click_distance
            && self.place_index_at_screen_point(point, size) == Some(source_index)
        {
            self.activate_place_index(source_index, point)
        } else {
            None
        };
        let hover_changed = self.refresh_hover(size);
        (hover_changed || activation.is_some(), activation)
    }

    fn place_index_at_screen_point(
        &self,
        point: ViewPoint,
        size: PhysicalSize<u32>,
    ) -> Option<usize> {
        if !self.places_sidebar_rect(size).contains(point) {
            return None;
        }
        self.place_row_rects(size)
            .into_iter()
            .find_map(|(index, rect)| rect.contains(point).then_some(index))
    }

    fn place_participates_in_dnd(&self, index: usize) -> bool {
        self.places
            .get(index)
            .is_some_and(|place| place.group.is_empty() && !place.network && place.device.is_none())
    }

    fn place_dnd_gap_index_is_valid(&self, index: usize) -> bool {
        let Some(first_index) = self
            .places
            .iter()
            .enumerate()
            .find_map(|(place_index, _place)| {
                self.place_participates_in_dnd(place_index)
                    .then_some(place_index)
            })
        else {
            return false;
        };
        let Some(last_index) =
            self.places
                .iter()
                .enumerate()
                .rev()
                .find_map(|(place_index, _place)| {
                    self.place_participates_in_dnd(place_index)
                        .then_some(place_index)
                })
        else {
            return false;
        };
        index >= first_index && index <= last_index.saturating_add(1)
    }

    fn place_row_rects(&self, size: PhysicalSize<u32>) -> Vec<(usize, ViewRect)> {
        let panel = self.places_panel_rect(size);
        if panel.width <= 0.0 || panel.height <= 0.0 {
            return Vec::new();
        }
        let mut rows = Vec::with_capacity(self.places.len());
        let top_padding = self.scale_metric(PLACES_SIDEBAR_TOP_PADDING);
        let title_height = self.scale_metric(PLACES_TITLE_HEIGHT);
        let padding_x = self.scale_metric(PLACES_SIDEBAR_PADDING_X);
        let section_height = self.scale_metric(PLACES_SECTION_HEIGHT);
        let row_height = self.scale_metric(PLACES_ROW_HEIGHT);
        let row_gap = self.scale_metric(PLACES_ROW_GAP);
        let mut y = panel.y + top_padding + title_height - self.places_scroll_y;
        let mut previous_group = None;
        for (index, place) in self.places.iter().enumerate() {
            if !place.group.is_empty() && previous_group != Some(place.group) {
                y += section_height;
            }
            let rect = ViewRect {
                x: panel.x + padding_x,
                y,
                width: (panel.width - padding_x * 2.0).max(1.0),
                height: row_height,
            };
            if rect.y < panel.bottom() && rect.bottom() > panel.y {
                rows.push((index, rect));
            }
            y += row_height + row_gap;
            previous_group = Some(place.group);
        }
        rows
    }

    fn place_gap_rects(&self, size: PhysicalSize<u32>) -> Vec<(usize, ViewRect)> {
        let panel = self.places_panel_rect(size);
        if panel.width <= 0.0 || panel.height <= 0.0 {
            return Vec::new();
        }
        let rows = self.place_row_rects(size);
        let dnd_rows = rows
            .into_iter()
            .filter(|(index, _rect)| self.place_participates_in_dnd(*index))
            .collect::<Vec<_>>();
        let Some((first_index, first_rect)) = dnd_rows.first().copied() else {
            return Vec::new();
        };
        let gap_height = self.scale_metric(8.0).max(4.0);
        let mut gaps = Vec::with_capacity(dnd_rows.len() + 1);
        let mut push_gap = |index: usize, center_y: f32, row: ViewRect| {
            let rect = ViewRect {
                x: row.x,
                y: center_y - gap_height / 2.0,
                width: row.width,
                height: gap_height,
            };
            if rect.y < panel.bottom() && rect.bottom() > panel.y {
                gaps.push((index, rect));
            }
        };
        push_gap(first_index, first_rect.y, first_rect);
        for pair in dnd_rows.windows(2) {
            let (index, rect) = pair[1];
            let (_, previous) = pair[0];
            push_gap(index, (previous.bottom() + rect.y) / 2.0, rect);
        }
        if let Some((last_index, last_rect)) = dnd_rows.last().copied() {
            push_gap(last_index + 1, last_rect.bottom(), last_rect);
        }
        gaps
    }

    fn place_gap_at_screen_point(
        &self,
        point: ViewPoint,
        size: PhysicalSize<u32>,
    ) -> Option<usize> {
        if !self.places_sidebar_rect(size).contains(point) {
            return None;
        }
        self.place_gap_rects(size)
            .into_iter()
            .find_map(|(index, rect)| rect.contains(point).then_some(index))
    }

    fn place_gap_at_screen_point_for_drag(
        &self,
        point: ViewPoint,
        size: PhysicalSize<u32>,
        drag: &ShellInternalDrag,
    ) -> Option<usize> {
        if let Some(index) = self.place_gap_at_screen_point(point, size) {
            return Some(index);
        }
        if !matches!(drag.source, ShellInternalDragSource::Place { .. }) {
            return None;
        }
        self.place_row_gap_at_screen_point(point, size)
    }

    fn place_row_gap_at_screen_point(
        &self,
        point: ViewPoint,
        size: PhysicalSize<u32>,
    ) -> Option<usize> {
        if !self.places_sidebar_rect(size).contains(point) {
            return None;
        }
        self.place_row_rects(size)
            .into_iter()
            .filter(|(index, _rect)| self.place_participates_in_dnd(*index))
            .find_map(|(index, rect)| {
                if !rect.contains(point) {
                    return None;
                }
                let before = point.y < rect.y + rect.height / 2.0;
                Some(if before {
                    index
                } else {
                    index.saturating_add(1)
                })
            })
    }

    fn place_gap_rect_for_index(&self, index: usize, size: PhysicalSize<u32>) -> Option<ViewRect> {
        self.place_gap_rects(size)
            .into_iter()
            .find_map(|(gap_index, rect)| (gap_index == index).then_some(rect))
    }

    fn places_sidebar_rect(&self, size: PhysicalSize<u32>) -> ViewRect {
        let width = self.places_sidebar_width(size);
        let y = self.pane_top_y();
        let height = (size.height as f32 - y - self.pane_margin()).max(1.0);
        ViewRect {
            x: 0.0,
            y,
            width,
            height,
        }
    }

    fn places_panel_rect(&self, size: PhysicalSize<u32>) -> ViewRect {
        let sidebar = self.places_sidebar_rect(size);
        if sidebar.width <= 0.0 || sidebar.height <= 0.0 {
            return ViewRect {
                x: sidebar.x,
                y: sidebar.y,
                width: 0.0,
                height: 0.0,
            };
        }
        let margin_x = self
            .scale_metric(PLACES_SIDEBAR_PANEL_MARGIN_X)
            .min(sidebar.width / 3.0);
        let margin_bottom = self
            .scale_metric(PLACES_SIDEBAR_PANEL_MARGIN_BOTTOM)
            .min(sidebar.height / 3.0);
        let y = sidebar.y;
        let task_top = self
            .places_task_area_rect(size)
            .map(|rect| rect.y - self.scale_metric(PLACES_TASK_AREA_GAP))
            .unwrap_or_else(|| sidebar.bottom() - margin_bottom);
        ViewRect {
            x: sidebar.x + margin_x,
            y,
            width: (sidebar.width - margin_x * 2.0).max(1.0),
            height: (task_top - y).max(1.0),
        }
    }

    fn places_task_area_rect(&self, size: PhysicalSize<u32>) -> Option<ViewRect> {
        if self.task_statuses.is_empty() {
            return None;
        }
        let sidebar = self.places_sidebar_rect(size);
        if sidebar.width <= 0.0 || sidebar.height <= 0.0 {
            return None;
        }
        let margin_x = self
            .scale_metric(PLACES_SIDEBAR_PANEL_MARGIN_X)
            .min(sidebar.width / 3.0);
        let margin_bottom = self
            .scale_metric(PLACES_SIDEBAR_PANEL_MARGIN_BOTTOM)
            .min(sidebar.height / 3.0);
        let min_height = self.scale_metric(52.0);
        let desired_height = self.scale_metric(PLACES_TASK_AREA_HEIGHT);
        let max_height = (sidebar.height - self.scale_metric(72.0)).max(0.0);
        let height = desired_height.min(max_height);
        if height < min_height {
            return None;
        }
        Some(ViewRect {
            x: sidebar.x + margin_x,
            y: sidebar.bottom() - margin_bottom - height,
            width: (sidebar.width - margin_x * 2.0).max(1.0),
            height,
        })
    }

    fn places_content_height(&self) -> f32 {
        let top_padding = self.scale_metric(PLACES_SIDEBAR_TOP_PADDING);
        let title_height = self.scale_metric(PLACES_TITLE_HEIGHT);
        let section_height = self.scale_metric(PLACES_SECTION_HEIGHT);
        let row_height = self.scale_metric(PLACES_ROW_HEIGHT);
        let row_gap = self.scale_metric(PLACES_ROW_GAP);
        if self.places.is_empty() {
            return top_padding * 2.0 + title_height;
        }

        let mut height = top_padding + title_height;
        let mut previous_group = None;
        for place in &self.places {
            if !place.group.is_empty() && previous_group != Some(place.group) {
                height += section_height;
            }
            height += row_height + row_gap;
            previous_group = Some(place.group);
        }
        height - row_gap + top_padding
    }

    fn max_places_scroll_y(&self, size: PhysicalSize<u32>) -> f32 {
        let panel = self.places_panel_rect(size);
        (self.places_content_height() - panel.height).max(0.0)
    }

    #[cfg(test)]
    fn places_scrollbar_thumb_rect(&self, size: PhysicalSize<u32>) -> Option<ViewRect> {
        self.places_scrollbar_rects(size).map(|(_, thumb)| thumb)
    }

    fn places_scrollbar_rects(&self, size: PhysicalSize<u32>) -> Option<(ViewRect, ViewRect)> {
        let panel = self.places_panel_rect(size);
        let max_scroll = self.max_places_scroll_y(size);
        if panel.width <= 0.0 || panel.height <= 0.0 || max_scroll <= f32::EPSILON {
            return None;
        }

        let scrollbar_margin = self.scale_metric(PLACES_SCROLLBAR_MARGIN);
        let scrollbar_width = self.scale_metric(PLACES_SCROLLBAR_WIDTH);
        let min_thumb_height = self.scale_metric(PLACES_SCROLLBAR_MIN_THUMB_HEIGHT);
        let track_height = (panel.height - scrollbar_margin * 2.0).max(1.0);
        let content_height = self.places_content_height().max(panel.height);
        let thumb_height = (panel.height / content_height * track_height)
            .clamp(min_thumb_height.min(track_height), track_height);
        let travel = (track_height - thumb_height).max(0.0);
        let scroll_ratio = if max_scroll <= f32::EPSILON {
            0.0
        } else {
            (self.places_scroll_y / max_scroll).clamp(0.0, 1.0)
        };
        let track = ViewRect {
            x: panel.right() - scrollbar_margin - scrollbar_width,
            y: panel.y + scrollbar_margin,
            width: scrollbar_width,
            height: track_height,
        };
        let thumb = ViewRect {
            x: track.x,
            y: panel.y + scrollbar_margin + travel * scroll_ratio,
            width: scrollbar_width,
            height: thumb_height,
        };
        Some((track, thumb))
    }

    fn context_target_for_screen_point(
        &self,
        point: ViewPoint,
        size: PhysicalSize<u32>,
    ) -> Option<ShellContextTarget> {
        if let Some(index) = self.place_index_at_screen_point(point, size) {
            let place = self.places.get(index)?;
            return Some(ShellContextTarget::Place {
                index,
                label: place.label.clone(),
                path: place.path.clone(),
                group: place.group,
                device: place.device.clone(),
                network: place.network,
                trash: place.trash,
                root: place.root,
                editable: place.editable,
            });
        }
        for geometry in self.pane_geometries(size) {
            if !geometry.content.contains(point) {
                continue;
            }
            let pane = self.pane_view(geometry.kind)?;
            if let Some(index) = self.pane_context_hit_test_screen_point(pane, geometry, point) {
                let entry = pane.entries.get(index)?;
                let selection_count = if pane.selection.contains(index) {
                    pane.selection.len().max(1)
                } else {
                    1
                };
                return Some(ShellContextTarget::Item {
                    pane: geometry.kind,
                    index,
                    path: self.entry_path_for_pane_view(pane, index)?,
                    is_dir: entry.is_dir,
                    selection_count,
                });
            }
            return Some(ShellContextTarget::Blank {
                pane: geometry.kind,
                path: pane.path.to_path_buf(),
            });
        }
        None
    }

    #[cfg_attr(not(test), allow(dead_code))]
    fn drop_target_at_screen_point(
        &self,
        point: ViewPoint,
        size: PhysicalSize<u32>,
    ) -> Option<ShellDropTarget> {
        if let Some(index) = self.place_index_at_screen_point(point, size) {
            let place = self.places.get(index)?;
            return Some(ShellDropTarget::Place {
                index,
                path: place.path.clone(),
            });
        }
        if self.places_visible && self.places_panel_rect(size).contains(point) {
            return Some(ShellDropTarget::PlacesBlank);
        }

        for geometry in self.pane_geometries(size) {
            if !geometry.content.contains(point) {
                continue;
            }
            let pane = self.pane_view(geometry.kind)?;
            if let Some(index) = self.pane_drop_hit_test_screen_point(pane, geometry, point) {
                let entry = pane.entries.get(index)?;
                return Some(ShellDropTarget::PaneItem {
                    pane: geometry.kind,
                    index,
                    path: self.entry_path_for_pane_view(pane, index)?,
                    is_dir: entry.is_dir,
                });
            }
            return Some(ShellDropTarget::PaneBlank {
                pane: geometry.kind,
                path: pane.path.to_path_buf(),
            });
        }

        None
    }

    fn drop_target_at_screen_point_for_drag(
        &self,
        point: ViewPoint,
        size: PhysicalSize<u32>,
        drag: &ShellInternalDrag,
    ) -> Option<ShellDropTarget> {
        if let Some(index) = self.place_gap_at_screen_point_for_drag(point, size, drag) {
            let target = ShellDropTarget::PlacesGap { index };
            if self.drag_can_drop_on_target(drag, &target) {
                return Some(target);
            }
        }
        let target = self.drop_target_at_screen_point(point, size)?;
        self.drag_can_drop_on_target(drag, &target)
            .then_some(target)
    }

    fn drag_can_drop_on_target(&self, drag: &ShellInternalDrag, target: &ShellDropTarget) -> bool {
        match target {
            ShellDropTarget::PlacesGap { index } => match &drag.source {
                ShellInternalDragSource::Place {
                    index: source_index,
                } => {
                    self.place_dnd_gap_index_is_valid(*index)
                        && self.place_participates_in_dnd(*source_index)
                        && *index != *source_index
                        && *index != source_index.saturating_add(1)
                }
                ShellInternalDragSource::PaneItem {
                    is_dir: true,
                    source_path,
                    ..
                } => drag.pane_source_directory_path().is_some() && !is_network_path(source_path),
                ShellInternalDragSource::PaneItem { is_dir: false, .. } => false,
            },
            ShellDropTarget::Place { index, .. } => {
                self.place_participates_in_dnd(*index)
                    && matches!(&drag.source, ShellInternalDragSource::PaneItem { .. })
            }
            ShellDropTarget::PaneItem { is_dir, path, .. } if *is_dir => {
                !drag.paths.iter().any(|source| source == path)
            }
            ShellDropTarget::PaneBlank { path, .. } => {
                !drag.paths.iter().any(|source| source == path)
            }
            ShellDropTarget::PaneItem { .. } | ShellDropTarget::PlacesBlank => false,
        }
    }

    fn drop_target_at_screen_point_for_external_drag(
        &self,
        point: ViewPoint,
        size: PhysicalSize<u32>,
        sources: &[PathBuf],
    ) -> Option<ShellDropTarget> {
        let target = self.drop_target_at_screen_point(point, size)?;
        self.external_drag_can_drop_on_target(sources, &target)
            .then_some(target)
    }

    fn external_drag_can_drop_on_target(
        &self,
        sources: &[PathBuf],
        target: &ShellDropTarget,
    ) -> bool {
        if sources.is_empty()
            || sources.iter().any(|path| is_network_path(path))
            || self
                .target_dir_for_drop_target(target)
                .is_some_and(|target_dir| is_network_path(&target_dir))
        {
            return false;
        }
        match target {
            ShellDropTarget::Place { index, path } => {
                self.place_participates_in_dnd(*index)
                    && !sources.iter().any(|source| source == path)
            }
            ShellDropTarget::PaneItem { is_dir, path, .. } if *is_dir => {
                !sources.iter().any(|source| source == path)
            }
            ShellDropTarget::PaneBlank { path, .. } => !sources.iter().any(|source| source == path),
            ShellDropTarget::PaneItem { .. }
            | ShellDropTarget::PlacesGap { .. }
            | ShellDropTarget::PlacesBlank => false,
        }
    }

    #[cfg_attr(not(test), allow(dead_code))]
    fn update_dnd_hover_target(&mut self, point: ViewPoint, size: PhysicalSize<u32>) -> bool {
        let next = self
            .internal_drag
            .as_ref()
            .and_then(|drag| self.drop_target_at_screen_point_for_drag(point, size, drag));
        let changed = self.dnd_hover_target != next;
        if changed {
            self.dnd_hover_target = next;
            self.dnd_hover_changes += 1;
        }
        changed
    }

    fn begin_external_drag(
        &mut self,
        sources: Vec<PathBuf>,
        point: ViewPoint,
        size: PhysicalSize<u32>,
    ) -> bool {
        self.pointer = Some(point);
        self.internal_drag = None;
        self.place_press = None;
        self.rubber_band = None;
        self.context_target = None;
        self.context_menu = None;
        self.drop_menu = None;
        let old_drag = self.external_drag.clone();
        self.external_drag = ShellExternalDrag::new(sources);
        let hover_changed = self.update_external_dnd_hover_target(point, size);
        old_drag != self.external_drag || hover_changed
    }

    fn update_external_drag(&mut self, point: ViewPoint, size: PhysicalSize<u32>) -> bool {
        self.pointer = Some(point);
        self.update_external_dnd_hover_target(point, size)
    }

    fn external_drag_sources(&self) -> Option<Vec<PathBuf>> {
        self.external_drag
            .as_ref()
            .map(|drag| drag.sources.clone())
            .filter(|sources| !sources.is_empty())
    }

    fn clear_external_drag(&mut self) -> bool {
        let changed = self.external_drag.take().is_some() || self.clear_dnd_hover_target();
        if changed {
            fika_log!("[fika-wgpu] external-dnd clear=1");
        }
        changed
    }

    fn finish_external_drag(
        &mut self,
        sources: Vec<PathBuf>,
        point: ViewPoint,
        size: PhysicalSize<u32>,
    ) -> Result<bool, String> {
        self.pointer = Some(point);
        let sources = normalized_external_drop_sources(sources);
        let drag_cleared = self.external_drag.take().is_some();
        let Some(target) =
            self.drop_target_at_screen_point_for_external_drag(point, size, &sources)
        else {
            let hover_cleared = self.clear_dnd_hover_target();
            return Ok(drag_cleared || hover_cleared);
        };
        let Some(target_dir) = self.target_dir_for_drop_target(&target) else {
            let hover_cleared = self.clear_dnd_hover_target();
            return Ok(drag_cleared || hover_cleared);
        };
        let old_menu = self.drop_menu.clone();
        self.drop_menu = Some(ShellDropMenu::new(sources, target_dir, target, point));
        self.context_menu = None;
        self.context_target = None;
        self.rubber_band = None;
        self.internal_drag = None;
        self.place_press = None;
        let _ = self.clear_dnd_hover_target();
        let changed = drag_cleared || old_menu != self.drop_menu;
        if changed {
            fika_log!(
                "[fika-wgpu] external-dnd-menu open=1 sources={} target={}",
                self.drop_menu
                    .as_ref()
                    .map(|menu| menu.sources.len())
                    .unwrap_or(0),
                self.drop_menu
                    .as_ref()
                    .map(|menu| menu.target.kind())
                    .unwrap_or("none")
            );
        }
        Ok(changed)
    }

    fn update_external_dnd_hover_target(
        &mut self,
        point: ViewPoint,
        size: PhysicalSize<u32>,
    ) -> bool {
        let next = self.external_drag.as_ref().and_then(|drag| {
            self.drop_target_at_screen_point_for_external_drag(point, size, &drag.sources)
        });
        let changed = self.dnd_hover_target != next;
        if changed {
            self.dnd_hover_target = next;
            self.dnd_hover_changes += 1;
        }
        changed
    }

    #[cfg_attr(not(test), allow(dead_code))]
    fn clear_dnd_hover_target(&mut self) -> bool {
        let changed = self.dnd_hover_target.take().is_some();
        if changed {
            self.dnd_hover_changes += 1;
        }
        changed
    }

    fn pane_drag_paths_for_index(&self, pane_id: ShellPaneId, index: usize) -> Vec<PathBuf> {
        let Some(pane) = self.pane_view(pane_id) else {
            return Vec::new();
        };
        if pane.selection.contains(index) {
            let paths = self
                .pane_selection(pane_id)
                .into_iter()
                .flat_map(|selection| selection.selected.iter())
                .copied()
                .filter_map(|index| self.entry_path_for_pane_view(pane, index))
                .collect::<Vec<_>>();
            if !paths.is_empty() {
                return paths;
            }
        }
        self.entry_path_for_pane_view(pane, index)
            .into_iter()
            .collect()
    }

    fn pane_drag_source_for_index(
        &self,
        pane_id: ShellPaneId,
        index: usize,
    ) -> Option<(PathBuf, bool, String)> {
        let pane = self.pane_view(pane_id)?;
        let entry = pane.entries.get(index)?;
        let path = self.entry_path_for_pane_view(pane, index)?;
        Some((path, entry.is_dir, entry.name.as_ref().to_string()))
    }

    fn drag_label_for_paths(paths: &[PathBuf], fallback: String) -> String {
        if paths.len() > 1 {
            return format!("{} items", paths.len());
        }
        paths
            .first()
            .and_then(|path| path.file_name())
            .and_then(|name| name.to_str())
            .filter(|name| !name.is_empty())
            .map(str::to_string)
            .unwrap_or(fallback)
    }

    fn begin_internal_drag_for_pane_item(
        &mut self,
        pane: ShellPaneId,
        index: usize,
        point: ViewPoint,
    ) -> bool {
        let Some((source_path, is_dir, fallback_label)) =
            self.pane_drag_source_for_index(pane, index)
        else {
            self.internal_drag = None;
            self.external_drag = None;
            return false;
        };
        let paths = self.pane_drag_paths_for_index(pane, index);
        if paths.is_empty() {
            self.internal_drag = None;
            self.external_drag = None;
            return false;
        }
        let label = Self::drag_label_for_paths(&paths, fallback_label);
        self.external_drag = None;
        self.internal_drag = Some(ShellInternalDrag::new(
            ShellInternalDragSource::PaneItem {
                pane,
                index,
                source_path,
                is_dir,
            },
            paths,
            label,
            point,
        ));
        true
    }

    fn begin_internal_drag_for_place(&mut self, index: usize, point: ViewPoint) -> bool {
        if !self.place_participates_in_dnd(index) {
            self.internal_drag = None;
            self.external_drag = None;
            return false;
        }
        let Some(place) = self.places.get(index) else {
            self.internal_drag = None;
            self.external_drag = None;
            return false;
        };
        self.external_drag = None;
        self.internal_drag = Some(ShellInternalDrag::new(
            ShellInternalDragSource::Place { index },
            vec![place.path.clone()],
            place.label.clone(),
            point,
        ));
        true
    }

    fn update_internal_drag(&mut self, point: ViewPoint, size: PhysicalSize<u32>) -> bool {
        let drag_changed = {
            let Some(drag) = self.internal_drag.as_mut() else {
                return false;
            };
            drag.update(point)
        };
        if !self.internal_drag.as_ref().is_some_and(|drag| drag.active) {
            return drag_changed;
        }
        let hover_cleared = if self
            .internal_drag
            .as_ref()
            .and_then(ShellInternalDrag::source_place_index)
            .is_some()
        {
            let place_hover_cleared = if self.hovered_place.is_some() {
                self.set_hovered_place(None)
            } else {
                false
            };
            let item_hover_cleared = if self.hovered_item.is_some() {
                self.set_hovered_item(None)
            } else {
                false
            };
            place_hover_cleared || item_hover_cleared
        } else {
            false
        };
        let hover_changed = self.update_dnd_hover_target(point, size);
        drag_changed || hover_cleared || hover_changed
    }

    fn finish_internal_drag(&mut self, point: ViewPoint, size: PhysicalSize<u32>) -> bool {
        let user_places_path = default_user_places_path();
        match self.finish_internal_drag_with_user_places_path(point, size, &user_places_path) {
            Ok(changed) => changed,
            Err(error) => {
                fika_log!("[fika-wgpu] dnd-error {error}");
                false
            }
        }
    }

    fn finish_internal_drag_with_user_places_path(
        &mut self,
        point: ViewPoint,
        size: PhysicalSize<u32>,
        user_places_path: &Path,
    ) -> Result<bool, String> {
        let Some(drag) = self.internal_drag.take() else {
            return Ok(false);
        };
        if !drag.active {
            let _ = self.clear_dnd_hover_target();
            return Ok(false);
        }
        let Some(target) = self.drop_target_at_screen_point_for_drag(point, size, &drag) else {
            let _ = self.clear_dnd_hover_target();
            return Ok(false);
        };
        if let ShellDropTarget::PlacesGap { index } = target {
            let changed =
                self.drop_internal_drag_to_places_gap(drag, index, user_places_path, size)?;
            let _ = self.clear_dnd_hover_target();
            return Ok(changed);
        }
        let Some(target_dir) = self.target_dir_for_drop_target(&target) else {
            let _ = self.clear_dnd_hover_target();
            return Ok(false);
        };
        if drag.paths.iter().any(|source| source == &target_dir) {
            let _ = self.clear_dnd_hover_target();
            return Ok(false);
        }
        let old_menu = self.drop_menu.clone();
        self.drop_menu = Some(ShellDropMenu::new(drag.paths, target_dir, target, point));
        self.context_menu = None;
        self.context_target = None;
        self.rubber_band = None;
        let _ = self.clear_dnd_hover_target();
        let changed = old_menu != self.drop_menu;
        if changed {
            fika_log!(
                "[fika-wgpu] dnd-menu open=1 sources={} target={}",
                self.drop_menu
                    .as_ref()
                    .map(|menu| menu.sources.len())
                    .unwrap_or(0),
                self.drop_menu
                    .as_ref()
                    .map(|menu| menu.target.kind())
                    .unwrap_or("none")
            );
        }
        Ok(changed)
    }

    fn drop_internal_drag_to_places_gap(
        &mut self,
        drag: ShellInternalDrag,
        index: usize,
        user_places_path: &Path,
        size: PhysicalSize<u32>,
    ) -> Result<bool, String> {
        match drag.source {
            ShellInternalDragSource::Place {
                index: source_index,
            } => self.move_place_to_gap(source_index, index, user_places_path, size),
            ShellInternalDragSource::PaneItem {
                source_path,
                is_dir: true,
                ..
            } => self.add_pane_folder_to_places_gap(source_path, index, user_places_path, size),
            ShellInternalDragSource::PaneItem { .. } => Ok(false),
        }
    }

    fn move_place_to_gap(
        &mut self,
        source_index: usize,
        gap_index: usize,
        user_places_path: &Path,
        size: PhysicalSize<u32>,
    ) -> Result<bool, String> {
        if source_index >= self.places.len()
            || gap_index > self.places.len()
            || !self.place_participates_in_dnd(source_index)
            || !self.place_dnd_gap_index_is_valid(gap_index)
            || gap_index == source_index
            || gap_index == source_index.saturating_add(1)
        {
            return Ok(false);
        }
        let place = self.places.remove(source_index);
        let insert_index = if gap_index > source_index {
            gap_index.saturating_sub(1)
        } else {
            gap_index
        }
        .min(self.places.len());
        let path = place.path.clone();
        let label = place.label.clone();
        self.places.insert(insert_index, place);
        save_shell_place_order(user_places_path, &self.places)?;
        self.context_target = None;
        self.context_menu = None;
        self.drop_menu = None;
        self.properties_overlay = None;
        self.rubber_band = None;
        self.clamp_places_scroll(size);
        self.places_changes += 1;
        self.refresh_hover(size);
        fika_log!(
            "[fika-wgpu] places-reorder label={:?} path={} from={} gap={} to={} changes={}",
            label,
            path.display(),
            source_index,
            gap_index,
            insert_index,
            self.places_changes
        );
        Ok(true)
    }

    fn add_pane_folder_to_places_gap(
        &mut self,
        path: PathBuf,
        gap_index: usize,
        user_places_path: &Path,
        size: PhysicalSize<u32>,
    ) -> Result<bool, String> {
        if is_network_path(&path) {
            return Ok(false);
        }
        if let Some(existing_index) = self.places.iter().position(|place| place.path == path) {
            if !self.place_participates_in_dnd(existing_index) {
                return Ok(false);
            }
            return self.move_place_to_gap(existing_index, gap_index, user_places_path, size);
        }
        let label = default_shell_place_label(&path);
        if !add_user_place_at_path(user_places_path, &path, label.clone())? {
            return Ok(false);
        }
        self.places = rebuild_shell_places_for_user_path(user_places_path);
        let Some(source_index) = self.places.iter().position(|place| place.path == path) else {
            save_shell_place_order(user_places_path, &self.places)?;
            return Ok(false);
        };
        let target_gap = gap_index.min(self.places.len());
        if self.move_place_to_gap(source_index, target_gap, user_places_path, size)? {
            return Ok(true);
        }
        save_shell_place_order(user_places_path, &self.places)?;
        self.context_target = None;
        self.context_menu = None;
        self.drop_menu = None;
        self.properties_overlay = None;
        self.rubber_band = None;
        self.clamp_places_scroll(size);
        self.places_changes += 1;
        self.refresh_hover(size);
        fika_log!(
            "[fika-wgpu] add-place label={:?} path={} gap={} places={} changes={}",
            label,
            path.display(),
            gap_index,
            self.places.len(),
            self.places_changes
        );
        Ok(true)
    }

    fn target_dir_for_drop_target(&self, target: &ShellDropTarget) -> Option<PathBuf> {
        match target {
            ShellDropTarget::PaneItem { path, is_dir, .. } if *is_dir => Some(path.clone()),
            ShellDropTarget::PaneBlank { path, .. } | ShellDropTarget::Place { path, .. } => {
                Some(path.clone())
            }
            ShellDropTarget::PaneItem { .. }
            | ShellDropTarget::PlacesGap { .. }
            | ShellDropTarget::PlacesBlank => None,
        }
    }

    fn open_context_target(&mut self, point: ViewPoint, size: PhysicalSize<u32>) -> bool {
        self.pointer = Some(point);
        let target = self.context_target_for_screen_point(point, size);
        let old_target = self.context_target.clone();
        let old_rubber_band_active = self.rubber_band.as_ref().is_some_and(|band| band.active);
        let rubber_band_cleared = self.rubber_band.take().is_some();
        let hover = target.as_ref().and_then(|target| match target {
            ShellContextTarget::Item { pane, index, .. } => Some(ShellPaneItemTarget {
                pane: *pane,
                index: *index,
            }),
            ShellContextTarget::Blank { .. } | ShellContextTarget::Place { .. } => None,
        });
        let hover_changed = self.set_hovered_item(hover);
        let place_hover = target.as_ref().and_then(|target| match target {
            ShellContextTarget::Place { index, .. } => Some(*index),
            ShellContextTarget::Item { .. } | ShellContextTarget::Blank { .. } => None,
        });
        let place_hover_changed = self.set_hovered_place(place_hover);

        let mut selection_changed = false;
        if let Some(ShellContextTarget::Item { pane, index, .. }) = target.as_ref() {
            self.active_pane = self.normalized_pane_id(*pane);
            selection_changed = if self
                .pane_selection(*pane)
                .is_some_and(|selection| selection.contains(*index))
            {
                self.pane_selection_mut(*pane)
                    .is_some_and(|selection| selection.focus_selected(*index))
            } else {
                self.pane_selection_mut(*pane)
                    .is_some_and(|selection| selection.apply_click(Some(*index), false, false))
            };
            if selection_changed {
                self.selection_changes += 1;
            }
        } else if let Some(ShellContextTarget::Blank { pane, .. }) = target.as_ref() {
            self.active_pane = self.normalized_pane_id(*pane);
            selection_changed = self
                .pane_selection_mut(*pane)
                .is_some_and(ShellSelection::clear);
            if selection_changed {
                self.selection_changes += 1;
            }
        }

        let target_changed = old_target != target;
        self.context_target = target;
        if target_changed {
            self.context_target_changes += 1;
            self.log_context_target();
        }

        target_changed
            || hover_changed
            || place_hover_changed
            || selection_changed
            || rubber_band_cleared
            || old_rubber_band_active
    }

    fn is_context_menu_open(&self) -> bool {
        self.context_menu.is_some()
    }

    fn is_drop_menu_open(&self) -> bool {
        self.drop_menu.is_some()
    }

    fn overlay_text_needed(&self) -> bool {
        self.internal_drag.as_ref().is_some_and(|drag| drag.active)
            || self.drop_menu.is_some()
            || self.context_menu.is_some()
            || self.properties_overlay.is_some()
            || self.task_detail_dialog.is_some()
            || self.trash_conflict_dialog.is_some()
    }

    fn close_drop_menu(&mut self) -> bool {
        if self.drop_menu.take().is_none() {
            return false;
        }
        fika_log!("[fika-wgpu] dnd-menu open=0");
        true
    }

    fn update_drop_menu_hover(&mut self, point: ViewPoint, size: PhysicalSize<u32>) -> bool {
        let row = self.drop_menu_row_at_screen_point(point, size);
        let Some(menu) = self.drop_menu.as_mut() else {
            return false;
        };
        let changed = menu.hovered_row != row;
        menu.hovered_row = row;
        changed
    }

    fn drop_menu_command_at_screen_point(
        &self,
        point: ViewPoint,
        size: PhysicalSize<u32>,
    ) -> Option<ShellDropMenuCommand> {
        let row = self.drop_menu_row_at_screen_point(point, size)?;
        drop_menu_items().get(row).map(|item| item.command)
    }

    fn drop_menu_row_at_screen_point(
        &self,
        point: ViewPoint,
        size: PhysicalSize<u32>,
    ) -> Option<usize> {
        let menu = self.drop_menu.as_ref()?;
        drop_menu_row_at_screen_point(menu, point, size, self.ui_scale())
    }

    fn activate_or_close_drop_menu_request(
        &mut self,
        point: ViewPoint,
        size: PhysicalSize<u32>,
    ) -> Option<ShellDropOperationRequest> {
        let command = self.drop_menu_command_at_screen_point(point, size);
        let menu = self.drop_menu.take();
        let Some(menu) = menu else {
            return None;
        };
        match command {
            Some(ShellDropMenuCommand::Mode { mode, privileged }) => {
                let request = ShellDropOperationRequest {
                    sources: menu.sources,
                    target_dir: menu.target_dir,
                    target: menu.target,
                    mode,
                    privileged,
                };
                self.pending_drop_request = Some(request.clone());
                self.dnd_drop_requests += 1;
                fika_log!(
                    "[fika-wgpu] dnd-drop-request sources={} target={} mode={} privileged={} requests={}",
                    request.sources.len(),
                    request.target_dir.display(),
                    request.mode.operation(),
                    request.privileged as u8,
                    self.dnd_drop_requests
                );
                Some(request)
            }
            Some(ShellDropMenuCommand::Cancel) | None => {
                fika_log!("[fika-wgpu] dnd-menu open=0");
                None
            }
        }
    }

    fn perform_drop_operation_request(
        &mut self,
        request: &ShellDropOperationRequest,
        size: PhysicalSize<u32>,
    ) -> Result<ShellPasteResult, String> {
        self.validate_drop_operation_request(request)?;
        let transfer = transfer_paths_with_privilege(
            request.target_dir.clone(),
            request.mode,
            request.sources.clone(),
            request.mode.label(),
            false,
            request.privileged,
        );
        let result = ShellPasteResult::from_transfer(&transfer);
        self.paste_changes += 1;
        fika_log!(
            "[fika-wgpu] dnd-transfer mode={} target={} success={} failure={} privileged={} changes={}",
            result.mode.label(),
            request.target_dir.display(),
            result.success_count,
            result.failure_count,
            result.privileged as u8,
            self.paste_changes
        );
        self.record_task_status(if result.failure_count > 0 {
            ShellTaskStatus::failed(
                if result.privileged {
                    format!("Administrator {} failed", result.mode.label())
                } else {
                    format!("{} failed", result.mode.label())
                },
                transfer_task_detail(
                    result.success_count,
                    result.failure_count,
                    &request.target_dir,
                    result.first_error.as_deref(),
                    result.administrator_available,
                ),
                result.privileged,
            )
        } else {
            ShellTaskStatus::completed(
                if result.privileged {
                    format!("Administrator {}", result.mode.label())
                } else {
                    result.mode.label().to_string()
                },
                transfer_task_detail(
                    result.success_count,
                    result.failure_count,
                    &request.target_dir,
                    None,
                    false,
                ),
                result.privileged,
            )
        });

        if result.changed() {
            self.context_target = None;
            self.context_menu = None;
            self.drop_menu = None;
            self.properties_overlay = None;
            self.create_dialog = None;
            self.rename_dialog = None;
            self.rubber_band = None;
            for affected_dir in transfer.result.refresh_dirs {
                self.reload_panes_showing_path(&affected_dir, size)?;
            }
        }
        Ok(result)
    }

    fn validate_drop_operation_request(
        &self,
        request: &ShellDropOperationRequest,
    ) -> Result<(), String> {
        if request.sources.is_empty() {
            return Err("no drop sources".to_string());
        }
        if is_network_path(&request.target_dir) {
            return Err("remote drop target is not available yet".to_string());
        }
        if request.sources.iter().any(|path| is_network_path(path)) {
            return Err("remote drop source is not available yet".to_string());
        }
        Ok(())
    }

    #[cfg(test)]
    fn open_context_menu(&mut self, point: ViewPoint, size: PhysicalSize<u32>) -> bool {
        self.open_context_menu_with_cache(point, size, &MimeApplicationCache::empty())
    }

    fn open_context_menu_with_cache(
        &mut self,
        point: ViewPoint,
        size: PhysicalSize<u32>,
        cache: &MimeApplicationCache,
    ) -> bool {
        let changed = self.open_context_target(point, size);
        let old_menu = self.context_menu.clone();
        self.drop_menu = None;
        self.context_menu = self.context_target.clone().map(|target| {
            let (open_with_apps, service_actions) = self.context_menu_dynamic_data(&target, cache);
            ShellContextMenu::with_dynamic(target, point, open_with_apps, service_actions)
        });
        let menu_changed = old_menu != self.context_menu;
        if menu_changed {
            fika_log!(
                "[fika-wgpu] context-menu open={} target={} actions={}",
                self.context_menu.is_some() as u8,
                self.context_target
                    .as_ref()
                    .map(ShellContextTarget::kind)
                    .unwrap_or("none"),
                self.context_menu
                    .as_ref()
                    .map(|menu| context_menu_items(menu).len())
                    .unwrap_or(0)
            );
        }
        changed || menu_changed
    }

    fn context_menu_dynamic_data(
        &self,
        target: &ShellContextTarget,
        cache: &MimeApplicationCache,
    ) -> (Vec<MimeApplication>, Vec<ServiceMenuAction>) {
        match target {
            ShellContextTarget::Item {
                pane,
                index,
                path,
                is_dir,
                ..
            } => {
                let mime_type = self
                    .pane_state(*pane)
                    .and_then(|pane| pane.entries.get(*index))
                    .and_then(|entry| entry.mime_type.as_deref());
                let open_with_apps = if file_ops::is_in_trash_files_dir(path)
                    || (*is_dir && is_network_path(path))
                {
                    Vec::new()
                } else if *is_dir {
                    open_with_applications_for_mime(cache, Some("inode/directory"))
                } else {
                    open_with_applications_for_mime(cache, mime_type)
                };
                let mut service_actions =
                    if file_ops::is_in_trash_files_dir(path) || is_network_path(path) {
                        Vec::new()
                    } else {
                        cache.service_actions_for_targets(
                            &self.service_menu_targets_for_context_item(
                                *pane, *index, *is_dir, mime_type,
                            ),
                        )
                    };
                self.append_builtin_ark_service_actions(target, &mut service_actions);
                (open_with_apps, service_actions)
            }
            ShellContextTarget::Blank { path, .. } => {
                let open_with_apps = if file_ops::is_trash_files_dir(&path) || is_network_path(path)
                {
                    Vec::new()
                } else {
                    open_with_applications_for_mime(cache, Some("inode/directory"))
                };
                let service_actions =
                    if file_ops::is_trash_files_dir(&path) || is_network_path(path) {
                        Vec::new()
                    } else {
                        cache.service_actions_for_targets(&[ServiceMenuTarget::new(
                            Some("inode/directory"),
                            true,
                        )])
                    };
                (open_with_apps, service_actions)
            }
            ShellContextTarget::Place { .. } => (Vec::new(), Vec::new()),
        }
    }

    fn append_builtin_ark_service_actions(
        &self,
        target: &ShellContextTarget,
        service_actions: &mut Vec<ServiceMenuAction>,
    ) {
        let Ok(items) = self.context_target_ark_items(target) else {
            return;
        };
        shell::ark::append_builtin_service_actions(&items, service_actions);
    }

    fn context_target_ark_items(
        &self,
        target: &ShellContextTarget,
    ) -> Result<Vec<ArkContextItem>, String> {
        let ShellContextTarget::Item {
            pane,
            index,
            path,
            is_dir,
            selection_count,
        } = target
        else {
            return Ok(Vec::new());
        };
        if file_ops::is_in_trash_files_dir(path) || is_network_path(path) {
            return Ok(Vec::new());
        }

        let pane_view = self
            .pane_view(*pane)
            .ok_or_else(|| "context target pane no longer exists".to_string())?;
        if *selection_count > 1 && pane_view.selection.contains(*index) {
            let items = self
                .pane_selection(*pane)
                .into_iter()
                .flat_map(|selection| selection.selected.iter())
                .copied()
                .filter_map(|selected| {
                    let entry = pane_view.entries.get(selected)?;
                    Some(ArkContextItem {
                        path: self.entry_path_for_pane_view(pane_view, selected)?,
                        is_dir: entry.is_dir,
                        mime_type: entry.mime_type.as_deref().map(str::to_string),
                    })
                })
                .collect::<Vec<_>>();
            return Ok(items);
        }

        let mime_type = pane_view
            .entries
            .get(*index)
            .and_then(|entry| entry.mime_type.as_deref())
            .map(str::to_string);
        Ok(vec![ArkContextItem {
            path: path.clone(),
            is_dir: *is_dir,
            mime_type,
        }])
    }

    fn service_menu_targets_for_context_item(
        &self,
        pane_id: ShellPaneId,
        index: usize,
        is_dir: bool,
        mime_type: Option<&str>,
    ) -> Vec<ServiceMenuTarget> {
        let Some(pane) = self.pane_view(pane_id) else {
            return vec![ServiceMenuTarget::new(
                mime_type.or_else(|| is_dir.then_some("inode/directory")),
                is_dir,
            )];
        };
        if pane.selection.contains(index) {
            let targets = self
                .pane_selection(pane_id)
                .into_iter()
                .flat_map(|selection| selection.selected.iter())
                .copied()
                .filter_map(|selected| pane.entries.get(selected))
                .map(|entry| {
                    ServiceMenuTarget::new(
                        entry
                            .mime_type
                            .as_deref()
                            .or_else(|| entry.is_dir.then_some("inode/directory")),
                        entry.is_dir,
                    )
                })
                .collect::<Vec<_>>();
            if !targets.is_empty() {
                return targets;
            }
        }
        vec![ServiceMenuTarget::new(
            mime_type.or_else(|| is_dir.then_some("inode/directory")),
            is_dir,
        )]
    }

    fn close_context_menu(&mut self) -> bool {
        if self.context_menu.take().is_none() {
            return false;
        }
        fika_log!("[fika-wgpu] context-menu open=0");
        true
    }

    fn activate_or_close_context_menu_command(
        &mut self,
        point: ViewPoint,
        size: PhysicalSize<u32>,
    ) -> Option<ShellContextMenuCommand> {
        let action = self.context_menu_command_at_screen_point(point, size);
        let menu_was_open = self.context_menu.take().is_some();
        if let Some(action) = action {
            self.context_menu_actions += 1;
            fika_log!(
                "[fika-wgpu] context-menu action={} target={} actions={}",
                action.as_str(),
                self.context_target
                    .as_ref()
                    .map(ShellContextTarget::kind)
                    .unwrap_or("none"),
                self.context_menu_actions
            );
            return Some(action);
        } else if menu_was_open {
            fika_log!("[fika-wgpu] context-menu open=0");
        }
        None
    }

    #[cfg(test)]
    fn activate_or_close_context_menu(
        &mut self,
        point: ViewPoint,
        size: PhysicalSize<u32>,
    ) -> Option<ShellContextMenuAction> {
        self.activate_or_close_context_menu_command(point, size)
            .and_then(|command| match command {
                ShellContextMenuCommand::Builtin(action) => Some(action),
                _ => None,
            })
    }

    fn context_menu_command_at_screen_point(
        &self,
        point: ViewPoint,
        size: PhysicalSize<u32>,
    ) -> Option<ShellContextMenuCommand> {
        let menu = self.context_menu.as_ref()?;
        if let Some(submenu) = menu.active_submenu
            && let Some(row) =
                context_submenu_row_at_screen_point(menu, submenu, point, size, self.ui_scale())
        {
            return context_submenu_actions(submenu, menu)
                .get(row)
                .map(|item| item.command.clone());
        }
        let row = context_menu_row_at_screen_point(menu, point, size, self.ui_scale())?;
        context_menu_items(menu)
            .get(row)
            .map(|item| item.command.clone())
    }

    #[cfg(test)]
    fn context_menu_action_at_screen_point(
        &self,
        point: ViewPoint,
        size: PhysicalSize<u32>,
    ) -> Option<ShellContextMenuAction> {
        self.context_menu_command_at_screen_point(point, size)
            .and_then(|command| match command {
                ShellContextMenuCommand::Builtin(action) => Some(action),
                _ => None,
            })
    }

    fn update_context_menu_hover(&mut self, point: ViewPoint, size: PhysicalSize<u32>) -> bool {
        let Some(snapshot) = self.context_menu.clone() else {
            return false;
        };
        let scale = self.ui_scale();
        let hovered_submenu_row = snapshot.active_submenu.and_then(|submenu| {
            context_submenu_row_at_screen_point(&snapshot, submenu, point, size, scale)
        });
        let hovered_row = if hovered_submenu_row.is_some()
            && context_menu_submenu_rect(&snapshot, size, scale)
                .is_some_and(|rect| rect.contains(point))
        {
            snapshot.hovered_row
        } else {
            context_menu_row_at_screen_point(&snapshot, point, size, scale)
        };
        let root_items = context_menu_items(&snapshot);
        let hovered_row = hovered_row.filter(|row| *row < root_items.len());
        let active_submenu = hovered_row
            .and_then(|row| root_items.get(row))
            .and_then(|item| item.submenu)
            .or_else(|| {
                hovered_submenu_row
                    .is_some()
                    .then_some(snapshot.active_submenu)
                    .flatten()
            });
        let Some(menu) = self.context_menu.as_mut() else {
            return false;
        };
        let changed = menu.hovered_row != hovered_row
            || menu.hovered_submenu_row != hovered_submenu_row
            || menu.active_submenu != active_submenu;
        menu.hovered_row = hovered_row;
        menu.hovered_submenu_row = hovered_submenu_row;
        menu.active_submenu = active_submenu;
        changed
    }

    fn log_context_target(&self) {
        match self.context_target.as_ref() {
            Some(ShellContextTarget::Item {
                pane,
                index,
                path,
                is_dir,
                selection_count,
                ..
            }) => fika_log!(
                "[fika-wgpu] context-target kind=item pane={} index={} dir={} selection={} path={} changes={}",
                pane.as_str(),
                index,
                *is_dir as u8,
                selection_count,
                path.display(),
                self.context_target_changes
            ),
            Some(ShellContextTarget::Blank { pane, path, .. }) => fika_log!(
                "[fika-wgpu] context-target kind=blank pane={} path={} changes={}",
                pane.as_str(),
                path.display(),
                self.context_target_changes
            ),
            Some(ShellContextTarget::Place {
                index,
                label,
                path,
                device,
                network,
                trash,
                root,
                editable,
                ..
            }) => fika_log!(
                "[fika-wgpu] context-target kind=place index={} label={:?} device={} mounted={} ejectable={} poweroff={} network={} trash={} root={} editable={} path={} changes={}",
                index,
                label,
                device.is_some() as u8,
                device.as_ref().is_none_or(|device| device.mounted) as u8,
                device.as_ref().is_some_and(|device| device.ejectable) as u8,
                device.as_ref().is_some_and(|device| device.can_power_off) as u8,
                *network as u8,
                *trash as u8,
                *root as u8,
                *editable as u8,
                path.display(),
                self.context_target_changes
            ),
            None => fika_log!(
                "[fika-wgpu] context-target kind=none changes={}",
                self.context_target_changes
            ),
        }
    }

    fn selected_directory_path(&self) -> Option<(ShellPaneId, PathBuf)> {
        let pane = self.active_pane();
        self.pane_selection(pane)?
            .focus_or_first_selected()
            .and_then(|index| self.directory_path_for_pane_index(pane, index))
            .map(|path| (pane, path))
    }

    fn selected_file_open_request(&self) -> Option<OpenFileRequest> {
        let pane = self.active_pane();
        let index = self.pane_selection(pane)?.focus_or_first_selected()?;
        let view = self.pane_view(pane)?;
        let entry = view.entries.get(index)?;
        if entry.is_dir {
            return None;
        }
        let path = self.entry_path_for_pane_view(view, index)?;
        Some(OpenFileRequest::from_path(path, entry.mime_type.as_deref()))
    }

    fn record_open_file_request(&mut self, request: &OpenFileRequest) {
        self.open_changes += 1;
        fika_log!(
            "[fika-wgpu] open path={} uri={} changes={}",
            request.path.display(),
            request.uri,
            self.open_changes
        );
        self.record_task_status(ShellTaskStatus::completed(
            "Opened",
            request.path.display().to_string(),
            false,
        ));
    }

    fn open_open_with_chooser_from_context(&mut self, cache: &MimeApplicationCache) -> bool {
        let chooser = match self.open_with_chooser_for_context(cache) {
            Ok(chooser) => chooser,
            Err(error) => {
                fika_log!("[fika-wgpu] open-with-error {error}");
                self.record_task_status(ShellTaskStatus::failed("Open With failed", error, false));
                return false;
            }
        };
        let changed = self.open_with_chooser.as_ref() != Some(&chooser);
        self.open_with_chooser = Some(chooser);
        self.context_menu = None;
        self.drop_menu = None;
        self.properties_overlay = None;
        self.create_dialog = None;
        self.rename_dialog = None;
        self.trash_conflict_dialog = None;
        self.rubber_band = None;
        if changed {
            self.reset_text_caret_blink();
            self.open_with_changes += 1;
            self.log_open_with_chooser_state();
        }
        changed
    }

    fn open_with_chooser_for_context(
        &self,
        cache: &MimeApplicationCache,
    ) -> Result<ShellOpenWithChooser, String> {
        let target = self.context_target.as_ref().ok_or_else(|| {
            format!(
                "target={} is not a file or folder target",
                self.context_target
                    .as_ref()
                    .map(ShellContextTarget::kind)
                    .unwrap_or("none")
            )
        })?;
        let item_mime_type = match target {
            ShellContextTarget::Item {
                pane, index, path, ..
            } if !file_ops::is_in_trash_files_dir(path) => self
                .pane_state(*pane)
                .and_then(|pane| pane.entries.get(*index))
                .ok_or_else(|| format!("entry index {index} is out of range"))?
                .mime_type
                .clone(),
            _ => None,
        };
        chooser_for_context_target(target, item_mime_type, cache)
    }

    fn is_open_with_chooser_open(&self) -> bool {
        self.open_with_chooser.is_some()
    }

    fn apply_open_with_command(&mut self, command: OpenWithCommand) -> bool {
        if command == OpenWithCommand::Cancel {
            return self.close_open_with_chooser();
        }
        let reset_caret_on_noop = matches!(
            &command,
            OpenWithCommand::Insert(_)
                | OpenWithCommand::Backspace
                | OpenWithCommand::Delete
                | OpenWithCommand::MoveLeft
                | OpenWithCommand::MoveRight
                | OpenWithCommand::MoveHome
                | OpenWithCommand::MoveEnd
        );
        let Some(chooser) = self.open_with_chooser.as_mut() else {
            return false;
        };
        if chooser.apply_command(command) {
            self.reset_text_caret_blink();
            self.open_with_changes += 1;
            self.log_open_with_chooser_state();
            true
        } else if reset_caret_on_noop {
            self.reset_text_caret_blink();
            true
        } else {
            false
        }
    }

    fn select_open_with_filtered_row(&mut self, row: usize) -> bool {
        let Some(chooser) = self.open_with_chooser.as_mut() else {
            return false;
        };
        if chooser.select_filtered_row(row) {
            self.open_with_changes += 1;
            self.log_open_with_chooser_state();
            true
        } else {
            false
        }
    }

    fn toggle_open_with_set_default(&mut self) -> bool {
        let Some(chooser) = self.open_with_chooser.as_mut() else {
            return false;
        };
        if chooser.toggle_set_as_default() {
            self.open_with_changes += 1;
            self.log_open_with_chooser_state();
            true
        } else {
            false
        }
    }

    fn set_open_with_query_cursor(&mut self, cursor: usize) -> bool {
        let Some(chooser) = self.open_with_chooser.as_mut() else {
            return false;
        };
        let cursor_changed = chooser.set_query_cursor(cursor);
        self.reset_text_caret_blink();
        if cursor_changed {
            self.open_with_changes += 1;
            self.log_open_with_chooser_state();
        }
        true
    }

    fn scroll_open_with_chooser_by(&mut self, delta_y: f32) -> bool {
        let Some(delta) = open_with_scroll_delta_rows(delta_y, self.ui_scale()) else {
            return false;
        };
        let Some(chooser) = self.open_with_chooser.as_mut() else {
            return false;
        };
        if chooser.scroll_rows(delta) {
            self.open_with_changes += 1;
            self.log_open_with_chooser_state();
            true
        } else {
            false
        }
    }

    fn open_with_launch_request(
        &self,
        cache: &MimeApplicationCache,
    ) -> Result<OpenWithLaunchRequest, String> {
        let chooser = self
            .open_with_chooser
            .as_ref()
            .ok_or_else(|| "Open With chooser is not open".to_string())?;
        launch_request_for_chooser(chooser, cache)
    }

    fn open_with_launch_request_for_context_application(
        &self,
        cache: &MimeApplicationCache,
        desktop_id: &str,
    ) -> Result<OpenWithLaunchRequest, String> {
        let target = self
            .context_target
            .as_ref()
            .ok_or_else(|| "Open With application requires a file or folder target".to_string())?;
        launch_request_for_context_application(target, cache, desktop_id)
    }

    fn service_menu_launch_request(
        &self,
        cache: &MimeApplicationCache,
        action_id: &str,
    ) -> Result<ServiceMenuLaunchRequest, String> {
        let paths = self
            .context_target_service_menu_paths()?
            .ok_or_else(|| "no service menu target paths".to_string())?;
        if shell::ark::is_builtin_action(action_id) {
            let target = self
                .context_target
                .as_ref()
                .ok_or_else(|| "Ark action requires a context target".to_string())?;
            let items = self.context_target_ark_items(target)?;
            if let Some(request) = shell::ark::builtin_launch_request(action_id, &items)? {
                return Ok(request);
            }
        }
        let plan = cache
            .service_action_launch_plan(action_id, &paths)
            .ok_or_else(|| format!("service action not found or unsupported: {action_id}"))?;
        Ok(ServiceMenuLaunchRequest {
            paths,
            app_name: plan.app_name.clone(),
            plan,
        })
    }

    fn context_target_service_menu_paths(&self) -> Result<Option<Vec<PathBuf>>, String> {
        match self.context_target.as_ref() {
            Some(ShellContextTarget::Item { .. }) => self.context_target_item_paths(),
            Some(ShellContextTarget::Blank { path, .. }) => Ok(Some(vec![path.clone()])),
            Some(ShellContextTarget::Place { path, .. }) => Ok(Some(vec![path.clone()])),
            None => Ok(None),
        }
    }

    fn set_open_with_chooser_error(&mut self, error: String) -> bool {
        let Some(chooser) = self.open_with_chooser.as_mut() else {
            fika_log!("[fika-wgpu] open-with-error {error}");
            return false;
        };
        if chooser.error.as_ref() == Some(&error) {
            return false;
        }
        chooser.error = Some(error);
        self.open_with_changes += 1;
        self.log_open_with_chooser_state();
        true
    }

    fn close_open_with_chooser(&mut self) -> bool {
        if self.open_with_chooser.take().is_none() {
            return false;
        }
        self.open_with_changes += 1;
        fika_log!(
            "[fika-wgpu] open-with open=0 changes={}",
            self.open_with_changes
        );
        true
    }

    fn close_open_with_chooser_after_success(&mut self, request: &OpenWithLaunchRequest) -> bool {
        if self.open_with_chooser.take().is_none() {
            return false;
        }
        self.open_with_changes += 1;
        fika_log!(
            "[fika-wgpu] open-with path={} app={:?} changes={}",
            request.path.display(),
            request.app_name,
            self.open_with_changes
        );
        true
    }

    fn open_with_chooser_click_at_screen_point(
        &self,
        point: ViewPoint,
        size: PhysicalSize<u32>,
    ) -> OpenWithChooserClick {
        let Some(chooser) = self.open_with_chooser.as_ref() else {
            return OpenWithChooserClick::Outside;
        };
        open_with_chooser_click_at_point(chooser, point, size, self.ui_scale())
    }

    fn log_open_with_chooser_state(&self) {
        match self.open_with_chooser.as_ref() {
            Some(chooser) => fika_log!(
                "[fika-wgpu] open-with open=1 path={} mime={} apps={} filtered={} category={} selected={} scroll={} set_default={} query={:?} cursor={} error={:?} changes={}",
                chooser.path.display(),
                chooser.mime_type.as_deref().unwrap_or("unknown"),
                chooser.applications.len(),
                chooser.filtered_count(),
                chooser
                    .selected_category_row()
                    .map(|category| category.label)
                    .unwrap_or("unknown"),
                chooser.selected_index,
                chooser.scroll_row,
                chooser.set_as_default as u8,
                chooser.query,
                chooser.query_cursor,
                chooser.error,
                self.open_with_changes
            ),
            None => fika_log!(
                "[fika-wgpu] open-with open=0 changes={}",
                self.open_with_changes
            ),
        }
    }

    fn context_target_copy_location_request(&self) -> Option<CopyLocationRequest> {
        match self.context_target.as_ref()? {
            ShellContextTarget::Item { path, .. } | ShellContextTarget::Place { path, .. } => {
                Some(CopyLocationRequest {
                    path: path.clone(),
                    text: copy_location_text_for_path(path),
                })
            }
            ShellContextTarget::Blank { .. } => None,
        }
    }

    fn context_target_pane(&self) -> Option<ShellPaneId> {
        match self.context_target.as_ref()? {
            ShellContextTarget::Item { pane, .. } | ShellContextTarget::Blank { pane, .. } => {
                Some(self.normalized_pane_id(*pane))
            }
            ShellContextTarget::Place { .. } => Some(self.active_pane()),
        }
    }

    fn context_target_device_action(
        &self,
        action: ShellContextMenuAction,
    ) -> Option<DeviceActionRequest> {
        let operation = device_place_operation_for_context_action(action)?;
        let ShellContextTarget::Place {
            label,
            path,
            device: Some(device),
            ..
        } = self.context_target.as_ref()?
        else {
            return None;
        };
        Some(DeviceActionRequest {
            id: device.id.clone(),
            label: label.clone(),
            action,
            operation,
            pane: self
                .context_target_pane()
                .unwrap_or_else(|| self.active_pane()),
            path: path.clone(),
        })
    }

    fn apply_device_place_operation_result(
        &mut self,
        request: &DeviceActionRequest,
        result: &DevicePlaceOperationResult,
        size: PhysicalSize<u32>,
    ) -> Result<(), String> {
        self.places = build_shell_places();
        self.clamp_places_scroll(size);
        self.context_target = None;
        self.context_menu = None;
        self.drop_menu = None;
        self.properties_overlay = None;
        self.rubber_band = None;
        self.internal_drag = None;
        self.external_drag = None;
        self.place_press = None;
        self.places_changes += 1;
        self.refresh_hover(size);
        match &result.result {
            Ok(mount_point) => {
                let mount_detail = mount_point
                    .as_ref()
                    .map(|path| path.display().to_string())
                    .unwrap_or_else(|| "-".to_string());
                fika_log!(
                    "[fika-wgpu] device-action-finished action={} id={:?} label={:?} mount={} changes={}",
                    request.action.as_str(),
                    result.device_id,
                    result.label,
                    mount_detail,
                    self.places_changes
                );
                self.record_task_status(ShellTaskStatus::completed(
                    request.action.label(),
                    format!("{} | mount {}", request.label, mount_detail),
                    false,
                ));
            }
            Err(error) => {
                fika_log!(
                    "[fika-wgpu] device-action-finished action={} id={:?} label={:?} error={error} changes={}",
                    request.action.as_str(),
                    result.device_id,
                    result.label,
                    self.places_changes
                );
                self.record_task_status(ShellTaskStatus::failed(
                    format!("{} failed", request.action.label()),
                    format!("{} | {error}", request.label),
                    false,
                ));
            }
        }

        if result.result.is_ok() && !matches!(request.operation, DevicePlaceOperation::Mount) {
            self.leave_device_path_after_unmount(request, size)?;
        }
        Ok(())
    }

    fn leave_device_path_after_unmount(
        &mut self,
        request: &DeviceActionRequest,
        size: PhysicalSize<u32>,
    ) -> Result<(), String> {
        if is_network_path(&request.path) || !request.path.is_absolute() {
            return Ok(());
        }
        let home = home_dir();
        let pane_ids = ShellPaneId::ALL
            .into_iter()
            .filter(|pane| {
                self.pane_state(*pane).is_some_and(|state| {
                    state.path == request.path || state.path.starts_with(&request.path)
                })
            })
            .collect::<Vec<_>>();
        for pane in pane_ids {
            self.load_path_in_pane(pane, home.clone(), size, true)?;
        }
        Ok(())
    }

    fn record_copy_location(&mut self, request: &CopyLocationRequest) {
        self.copy_location_changes += 1;
        fika_log!(
            "[fika-wgpu] copy-location path={} text={:?} changes={}",
            request.path.display(),
            request.text,
            self.copy_location_changes
        );
        self.record_task_status(ShellTaskStatus::completed(
            "Copied Location",
            request.path.display().to_string(),
            false,
        ));
    }

    fn record_task_status(&mut self, status: ShellTaskStatus) {
        self.task_statuses.record(status);
        if let Some(status) = self.task_statuses.front() {
            fika_log!(
                "[fika-wgpu] task-status kind={:?} label={:?} privileged={} detail={:?} changes={}",
                status.kind,
                status.label,
                status.privileged as u8,
                status.detail,
                self.task_statuses.change_generation()
            );
        }
    }

    fn finish_task_status(&mut self, task_id: ShellTaskId, status: ShellTaskStatus) {
        self.task_statuses.finish(task_id, status);
    }

